  testMatchFirstByte =>
    result := "ABC" match: [
      <<first:8, _/binary>> -> first;
      _ -> 0
    ]
    self assert: result equals: 65

  testMatchRestBinary =>
    result := "ABC" match: [
      <<_:8, rest/binary>> -> rest size;
