/// Account actor — an independent process managing a single bank balance
///
/// Each Account is a BEAM process. Deposits and withdrawals are message sends,
/// making them inherently serialised per-account. Overdraft protection raises
/// a structured error via `self error:`
///
/// Usage:
///   acct := Account spawn
///   acct deposit: 500
///   acct balance          // => 500
///   acct withdraw: 200    // => 300
///   acct withdraw: 9999   // => ERROR: Insufficient funds
Actor subclass: Account
  state: balance = 0
  state: owner = ""

  deposit: amount =>
    amount < 0 ifTrue: [self error: "Amount must be non-negative"]
    self.balance := self.balance + amount
    self.balance

  withdraw: amount =>
    (amount < 0) ifTrue: [self error: "Amount must be non-negative"]
    self.balance < amount
      ifTrue: [
        self
          error: "Insufficient funds (balance: "
            ++ self.balance printString
            ++ ", requested: "
            ++ amount printString
            ++ ")"
      ]
    self.balance := self.balance - amount
    self.balance

  balance => self.balance

  setOwner: name => self.owner := name

  getOwner => self.owner

/// Bank actor — a registry and factory for Account actors
///
/// The Bank maintains a Dictionary mapping account names to Account actor
/// references. Opening an account spawns a new Account process and registers
/// it. Looking up an account returns the live actor reference
///
/// Usage:
///   bank := Bank spawn
///   bank openAccount: "Alice"
///   alice := bank accountFor: "Alice"
///   alice deposit: 1000
Actor subclass: Bank
  state: accounts = #{}
  state: lastCreated = nil

  openAccount: name =>
    self.lastCreated := Account spawn
    self.lastCreated setOwner: name
    self.accounts := self.accounts at: name put: self.lastCreated
    self.lastCreated

  accountFor: name =>
    self.accounts at: name ifAbsent: [
      self error: "No account found for: " ++ name
    ]

  allAccounts => self.accounts

/// Transaction — an immutable value recording a transfer
///
/// Transactions are value objects (`Value subclass:`), not actors. They capture
/// the details of a transfer as an immutable record. Getters (`amount`,
/// `from`, `to`, `timestamp`, `status`) are auto-generated by `Value`.
///
/// Usage:
///   txn := Transaction amount: 250 from: "Alice" to: "Bob" status: "completed" timestamp: nil
///   txn amount   // => 250
///   txn status   // => "completed"
Value subclass: Transaction
  field: amount = 0
  field: from = ""
  field: to = ""
  field: timestamp = nil
  field: status = "pending"

/// TransferAgent actor — coordinates transfers between two Account actors
///
/// A TransferAgent moves money between accounts by sending withdraw and
/// deposit messages synchronously. Each Account handles its own validation
/// (e.g. overdraft protection) independently
///
/// This demonstrates the actor coordination pattern: the TransferAgent
/// orchestrates two independent actors, and each actor enforces its own
/// invariants
///
/// Usage:
///   agent := TransferAgent spawn
///   agent transfer: 250 from: alice to: bob
Actor subclass: TransferAgent
  state: lastAmount = 0

  transfer: amount from: source to: destination =>
    source withdraw: amount
    destination deposit: amount
    self.lastAmount := amount

  getLastAmount => self.lastAmount

// BUnit tests for the Transaction value type
