TestCase subclass: TransactionTest

  testDefaultAmount => self assert: Transaction new amount equals: 0

  testDefaultFrom => self assert: Transaction new from equals: ""

  testDefaultTo => self assert: Transaction new to equals: ""

  testDefaultStatus => self assert: Transaction new status equals: "pending"

  testDefaultTimestampIsNil =>
