    self assert: txn1 amount equals: 100
    self assert: txn2 amount equals: 200

/// Chat Member Actor — Part of Chat Room Demo
///
/// ChatMember represents a chat participant with a name, inbox, and room ref
/// It demonstrates:
/// - Actor-to-actor references (room field)
/// - Receiving formatted messages from other actors
/// - State mutations (name, inbox, room)
///
/// Try it in the REPL:
///   $ beamtalk repl
///   > :load examples/chat-room/message.bt
///   > :load examples/chat-room/chat_room.bt
///   > :load examples/chat-room/chat_member.bt
///   > room := ChatRoom spawn
///   > alice := ChatMember spawn
///   > alice setName: "Alice"
///   > alice setRoom: room
///   > room join: alice
///   > room say: "Hello!" from: "Alice"
///
/// See examples/chat-room/README.md for a full walkthrough
Actor subclass: ChatMember
  state: name = "Guest"  // Member's display name
  state: inbox = #()  // List of received messages
  state: room = nil  // Reference to the ChatRoom actor

  // Set the member's display name
  setName: newName => self.name := newName

  // Set the chat room reference
  // Demonstrates: Storing an actor reference in a field
  setRoom: newRoom => self.room := newRoom

  // Receive a message (called by ChatRoom during broadcast)
  // Demonstrates: List concatenation for inbox
  receiveMessage: msg => self.inbox := self.inbox ++ #(msg)

  // Send a message via the room, using own name as sender
  // Demonstrates: Calling method on actor reference stored in field
  say: message => self.room say: message from: self.name

  // Return received messages
  getInbox => self.inbox

  // Return member's name
  getName => self.name

// Chat Room Demo — Multi-Actor Showcase
//
// This example demonstrates:
// 1. **Actors** — ChatRoom and ChatMember as independent processes
// 2. **Message passing** — sync-by-default messages between actors
// 3. **Collections** — Set for member tracking, List for message history
// 4. **Value types** — Message class (Object subclass) for structured data
// 5. **Blocks** — iteration with do: for broadcasting
// 6. **State management** — mutable actor state
// 7. **Live interaction** — REPL as the chat interface
//
// Try it in the REPL:
//   $ beamtalk repl
//   > :load examples/chat-room/message.bt
//   > :load examples/chat-room/chat_room.bt
//   > :load examples/chat-room/chat_member.bt
//   > room := ChatRoom spawn
//   > alice := ChatMember spawn
//   > alice setName: "Alice"
//   > alice setRoom: room
//   > room join: alice
//   > room say: "Hello!" from: "Alice"
//   > room getHistory
//
// See examples/chat-room/README.md for a full walkthrough

// ===========================================================================
// CHATROOM ACTOR
// ===========================================================================

/// ChatRoom manages a Set of member actors and a List of message strings
/// It demonstrates:
/// - Storing actor references (PIDs) in a Set
/// - String concatenation for formatted messages
/// - Broadcasting via do: iteration over actor Set
/// - List concatenation for message history
Actor subclass: ChatRoom
  state: members = Set new  // Set of ChatMember actor references
  state: history = #()  // List of formatted message strings

  // Add a member to the room
  // Demonstrates: Set add: operation with actor references
  join: member => self.members := self.members add: member

  // Remove a member from the room
  // Demonstrates: Set remove: operation
  leave: member => self.members := self.members remove: member

  // Broadcast a message to all members
  // Demonstrates:
  // - List concatenation (++) for history
  // - Set do: iteration with blocks
  // - Calling actor methods inside block (m receiveMessage:)
  say: text from: senderName =>
    self.history := self.history ++ #(senderName ++ ": " ++ text)
    self.members do: [:m | m receiveMessage: senderName ++ ": " ++ text]

  // Return current online members
  // Demonstrates: Returning a Set of actor references
  online => self.members

  // Return message history
  // Demonstrates: Returning a List of formatted strings
  getHistory => self.history

/// Message — immutable value type for chat messages
///
/// Demonstrates:
/// 1. **Value types** — `Value subclass:` (not Actor), no process overhead
/// 2. **State** — text and sender fields with defaults
/// 3. **Immutability** — enforced by the compiler; mutations are errors
/// 4. **Auto-generated getters** — `text` and `sender` provided by Value
///
/// Usage in REPL:
///   > :load examples/chat-room/message.bt
///   > msg := Message text: "Hello!" sender: "Alice"
///   > msg text
///   > msg describe
Value subclass: Message
  field: text = ""
  field: sender = "Anonymous"

  // Human-readable description
  describe => self.sender ++ ": " ++ self.text

/// Moderator — Actor subclass of ChatMember
///
/// Demonstrates:
/// 1. **Actor inheritance** — ChatMember subclass: Moderator
/// 2. **super calls** — Moderator overrides say: to add "[MOD]" prefix
/// 3. **New methods** — kick: and mute: for moderation actions
///
/// Usage in REPL:
///   > :load examples/chat-room/message.bt
///   > :load examples/chat-room/chat_room.bt
///   > :load examples/chat-room/chat_member.bt
///   > :load examples/chat-room/moderator.bt
///   > room := ChatRoom spawn
///   > mod := Moderator spawn
///   > mod setName: "Admin"
///   > mod setRoom: room
///   > room join: mod
///   > mod say: "Welcome!"
ChatMember subclass: Moderator
  state: muted = Set new  // Set of muted member names

  // Override say to prefix messages with [MOD]
  // Demonstrates: super call to parent method
  say: message => super say: "[MOD] " ++ message

  // Kick a member from the room
  // Demonstrates: Actor-to-actor method calls
  kick: member => self.room leave: member

  // Mute a member by name
  mute: memberName => self.muted := self.muted add: memberName

  // Unmute a member by name
  unmute: memberName => self.muted := self.muted remove: memberName

  // Check if a member name is muted
  isMuted: memberName => self.muted includes: memberName

  // Return the set of muted member names
  getMuted => self.muted

