/// Counter actor class example
/// A simple stateful actor that can increment, decrement, and return its value
///
/// Try it in the REPL:
///   $ beamtalk repl
///   > :load "examples/getting-started/src/counter.bt"
///   nil
///   > c := Counter spawn
///   > c increment
///   > c increment
///   > c getValue
///   2
///   > c decrement
///   > c getValue
///   1
///
/// Fire-and-forget with `!` (async cast, returns nil immediately):
///   > c increment!
///   nil
///   > c increment!
///   nil
///   > c getValue
///   3
///
/// See examples/repl-tutorial.md for a full beginner's guide
Actor subclass: Counter
  state: value :: Integer = 0

  /// Increase the counter by one.
  ///
  /// ## Examples
  /// ```beamtalk
  /// c := Counter spawn
  /// c increment
  /// c getValue              // => 1
  /// ```
  increment -> Integer => self.value := self.value + 1

  /// Decrease the counter by one.
  ///
  /// ## Examples
  /// ```beamtalk
  /// c := Counter spawn
  /// c decrement
  /// c getValue              // => -1
  /// ```
  decrement -> Integer => self.value := self.value - 1

  /// Return the current counter value.
  ///
  /// ## Examples
  /// ```beamtalk
  /// c := Counter spawn
  /// c getValue              // => 0
  /// ```
  getValue => self.value

/// Towers of Hanoi
/// A classic recursive algorithm that moves n disks between three pegs
///
/// Try it in the REPL:
///   $ beamtalk repl
///   > :load examples/hanoi.bt
///   > h := Hanoi new
///   > h solve: 3 from: "A" to: "C" via: "B"
///   Move disk from A to C
///   Move disk from A to B
///   Move disk from C to B
///   Move disk from A to C
///   Move disk from B to A
///   Move disk from B to C
///   Move disk from A to C
///   nil
Value subclass: Hanoi

  solve: n from: source to: target via: auxiliary =>
    (n > 0)
      ifTrue: [
        self
          solve: n - 1
          from: source
          to: auxiliary
          via: target
        self traceCr: "Move disk from " ++ source ++ " to " ++ target
        self
          solve: n - 1
          from: auxiliary
          to: target
          via: source
      ]
      ifFalse: [nil]

