/// Adapter Pattern — CelsiusThermometer (adaptee)
/// Intent: Convert the interface of a class into another interface clients expect.
/// Adapter lets classes work together that couldn't otherwise because of
/// incompatible interfaces.
///
/// CelsiusThermometer is an existing class whose interface we cannot change.
/// It speaks only Celsius. CelsiusToFahrenheitAdapter wraps it to speak Fahrenheit.
Value subclass: CelsiusThermometer
  field: celsius = 0.0

  /// Create a thermometer whose reading is degrees Celsius.
  class withCelsius: degrees => self new: #{#celsius => degrees}

  /// Return the current temperature in degrees Celsius.
  readCelsius => self.celsius

/// Adapter Pattern — CelsiusToFahrenheitAdapter
/// Wraps a CelsiusThermometer (adaptee) and exposes the FahrenheitThermometer
/// interface (target), translating units on the fly.
///
/// Usage:
///   sensor  := CelsiusThermometer withCelsius: 100.0.
///   adapted := CelsiusToFahrenheitAdapter wrap: sensor.
///   adapted readFahrenheit   // => 212.0
///   adapted readCelsius      // => 100.0
FahrenheitThermometer subclass: CelsiusToFahrenheitAdapter
  field: adaptee = nil

  /// Wrap a CelsiusThermometer so it can be used as a FahrenheitThermometer.
  class wrap: thermometer => self new: #{#adaptee => thermometer}

  /// Return the adaptee's reading in degrees Celsius (pass-through).
  readCelsius => self.adaptee readCelsius

  /// Convert the adaptee's Celsius reading to Fahrenheit.
  readFahrenheit => self.adaptee readCelsius * 9.0 / 5.0 + 32.0

/// Adapter Pattern — FahrenheitThermometer (target interface)
/// The interface that client code expects: readings in both Fahrenheit and Celsius.
Value subclass: FahrenheitThermometer

  /// Return the current temperature in degrees Fahrenheit.
  readFahrenheit => self subclassResponsibility

  /// Return the current temperature in degrees Celsius.
  readCelsius => self subclassResponsibility

/// Builder Pattern — HtmlBuilder
/// Fluently assembles HtmlElement objects step-by-step. Because all values are
/// immutable, each step returns a new builder — callers chain calls and finish
/// with build to obtain the completed HtmlElement.
///
/// Usage:
///   el := ((HtmlBuilder buildTag: "a")
///             withAttr: "href" value: "https://example.com")
///             withText: "Click here";
///             build.
///   el render   // => "<a href="https://example.com">Click here</a>"
Value subclass: HtmlBuilder
  field: element = nil

  /// Begin building a new element with the given tag name.
  class buildTag: t => self new: #{#element => (HtmlElement tag: t)}

  /// Add an HTML attribute to the element under construction.
  withAttr: key value: val =>
    self withElement: (self.element attribute: key value: val)

  /// Set the text content of the element under construction.
  withText: t =>
    self withElement: (self.element text: t)

  /// Finalise construction and return the built HtmlElement.
  build => self.element

/// Builder Pattern — HtmlElement (the product)
/// Intent: Separate the construction of a complex object from its representation.
///
/// HtmlElement is an immutable value object. Its state is assembled step-by-step
/// by HtmlBuilder. Callers never construct HtmlElement directly.
Value subclass: HtmlElement
  field: tag = "div"
  field: attributes = #{}
  field: content = ""

  /// Begin with the given HTML tag name and empty attributes and content.
  class tag: t => self new: #{#tag => t}

  /// Return a new element with the given attribute added.
  attribute: key value: val =>
    self withAttributes: (self.attributes at: key put: val)

  /// Return a new element with the text content replaced.
  text: t =>
    self withContent: t

  /// Render to an HTML string.
  render =>
    attrs := self.attributes
    attrStr := attrs keys inject: "" into: [:acc :k |
      acc ++ " {k}=""{attrs at: k}"""
    ]
    "<{self.tag}{attrStr}>{self.content}</{self.tag}>"

/// Command Pattern — CommandHistory (invoker)
/// Executes commands on a TextBuffer, tracking buffer snapshots for undo support.
/// Each execute: runs the command first, then saves the previous buffer state.
/// undo restores the most recent saved state. No command needs to implement its own undo logic.
///
/// Usage:
///   h := CommandHistory on: (TextBuffer withText: "hello").
///   h := h execute: (InsertCommand at: 6 insert: " world").
///   h buffer text    // => "hello world"
///   h := h undo.
///   h buffer text    // => "hello"
Value subclass: CommandHistory
  field: buffer = nil
  field: history = #()  // stack of prior buffer snapshots

  /// Create a history whose initial buffer state is aBuffer.
  class on: aBuffer => self new: #{#buffer => aBuffer}

  /// Execute a command, save the current buffer as a snapshot, update the buffer.
  execute: command =>
    nextBuffer := command execute: self.buffer
    (self withHistory: (self.history add: self.buffer)) withBuffer: nextBuffer

  /// Restore the most recent snapshot, removing it from the stack.
  undo =>
    self.history isEmpty ifTrue: [^self]
    (self withBuffer: self.history last) withHistory: (self.history take: self.history size - 1)

  /// Return the current buffer state.
  buffer => self.buffer

  /// Return true if there is at least one snapshot available to undo.
  canUndo => self.history isNotEmpty

/// Command Pattern — DeleteCommand (concrete command)
/// Deletes len characters starting at pos (1-based).
/// Undo is provided by CommandHistory snapshot rollback, not by this class.
TextCommand subclass: DeleteCommand
  field: position = 1
  field: length = 0

  /// Create a command that will delete len characters starting at 1-based position pos.
  class from: pos length: len => self new: #{#position => pos, #length => len}

  /// Delete this command's character range from buffer.
  execute: buffer => buffer deleteFrom: self.position length: self.length

/// Command Pattern — InsertCommand (concrete command)
/// Inserts a string at a given position (1-based).
TextCommand subclass: InsertCommand
  field: position = 1
  field: text = ""

  /// Create a command that will insert str at 1-based position pos.
  class at: pos insert: str => self new: #{#position => pos, #text => str}

  /// Insert this command's text into buffer at the stored position.
  execute: buffer => buffer insertAt: self.position text: self.text

/// Command Pattern — TextBuffer (receiver)
/// Intent: Encapsulate a request as an object, letting you parameterise clients
/// with different requests, queue or log requests, and support undoable operations.
///
/// TextBuffer holds text content. Commands operate on it by calling insertAt:text:
/// and deleteFrom:length:. Because value objects are immutable, both methods return
/// a new TextBuffer — CommandHistory stores the successive snapshots.
Value subclass: TextBuffer
  field: text = ""

  /// Create a buffer pre-populated with the given string.
  class withText: t => self new: #{#text => t}

  /// Return the current text content of the buffer.
  text => self.text

  /// Return a new buffer with str inserted at position pos (1-based).
  insertAt: pos text: str =>
    pos < 1 ifTrue: [self error: "insertAt:text: pos must be >= 1"]
    before := self.text take: pos - 1
    after := self.text drop: pos - 1
    TextBuffer withText: before ++ str ++ after

  /// Return a new buffer with len characters removed starting at pos (1-based).
  deleteFrom: pos length: len =>
    pos < 1 ifTrue: [self error: "deleteFrom:length: pos must be >= 1"]
    len < 0 ifTrue: [self error: "deleteFrom:length: len must be >= 0"]
    before := self.text take: pos - 1
    after := self.text drop: pos - 1 + len
    TextBuffer withText: before ++ after

/// Command Pattern — TextCommand (abstract command)
/// Declares execute:, which takes a TextBuffer and returns a new TextBuffer.
/// Undo is handled by CommandHistory, which saves buffer snapshots before each
/// command so no command needs to implement its own reverse logic.
Value subclass: TextCommand

  /// Apply this command to buffer and return the resulting buffer.
  execute: _buffer => self subclassResponsibility

/// Composite Pattern — FsDir (composite)
/// A directory that holds any number of FsEntry objects (files or subdirectories).
/// Because value objects are immutable, add: returns a new FsDir.
/// Implements the same interface as FsFile (name, size, describe:) via duck typing.
///
/// Usage:
///   f1  := FsFile name: "main.bt" size: 120.
///   f2  := FsFile name: "lib.bt"  size: 340.
///   src := ((FsDir name: "src") add: f1) add: f2.
///   src size          // => 460
///   src describe: ""
///   // => "src/ (460 bytes)\n  main.bt (120 bytes)\n  lib.bt (340 bytes)"
FsEntry subclass: FsDir
  field: name = ""
  field: children = #()

  /// Create an empty directory with the given name.
  class name: n => self new: #{#name => n}

  /// Return the directory name.
  name => self.name

  /// Return a new FsDir with entry appended to children.
  add: entry => self withChildren: (self.children add: entry)

  /// Total size is the recursive sum of all children.
  size => self.children inject: 0 into: [:acc :child | acc + child size]

  /// Return a multi-line tree string; each child is indented two spaces beyond indent.
  describe: indent =>
    total := self size
    childLines := self.children inject: "" into: [:acc :child |
      acc ++ "\n" ++ (child describe: indent ++ "  ")
    ]
    "{indent}{self.name}/ ({total} bytes){childLines}"

/// Composite Pattern — FsEntry (abstract component)
/// Intent: Compose objects into tree structures to represent part-whole hierarchies.
/// Composite lets clients treat individual objects (FsFile) and compositions
/// (FsDir) uniformly through a single interface.
Value subclass: FsEntry

  /// Return the name of this entry (file or directory name, without path).
  name => self subclassResponsibility

  /// Return the total byte size of this entry (recursive for directories).
  size => self subclassResponsibility

  /// Return a human-readable string representation, indented by indent.
  describe: _indent => self subclassResponsibility

/// Composite Pattern — FsFile (leaf)
/// A single file with a fixed name and byte size. Has no children.
/// Implements the same interface as FsDir (name, size, describe:) via duck typing.
///
/// Usage:
///   f := FsFile name: "main.bt" size: 120.
///   f size            // => 120
///   f describe: ""    // => "main.bt (120 bytes)"
FsEntry subclass: FsFile
  field: name = ""
  field: size = 0

  /// Create a file entry with the given name and byte size.
  class name: n size: s => self new: #{#name => n, #size => s}

  /// Return the file name.
  name => self.name

  /// Return the file size in bytes.
  size => self.size

  /// Return "indent<name> (<size> bytes)".
  describe: indent => "{indent}{self.name} ({self.size} bytes)"

/// Decorator Pattern — Beverage (abstract component)
/// Intent: Attach additional responsibilities to an object dynamically.
/// Decorators provide a flexible alternative to subclassing for extending
/// functionality by wrapping objects rather than changing their class.
///
/// Any Beverage has a description and a cost. Both concrete beverages and
/// condiment decorators satisfy this interface.
Value subclass: Beverage

  /// Return a human-readable description of this beverage and its condiments.
  description => self subclassResponsibility

  /// Return the total price in dollars.
  cost => self subclassResponsibility

/// Decorator Pattern — CondimentDecorator (abstract decorator)
/// Wraps any beverage object. Concrete subclasses override description and cost to
/// add their own contribution on top of the wrapped drink's values.
Beverage subclass: CondimentDecorator
  field: beverage = nil

  /// Wrap aBeverage so this condiment's description and cost are layered on top.
  class wrap: aBeverage => self new: #{#beverage => aBeverage}

/// Decorator Pattern — Espresso (concrete component)
Beverage subclass: Espresso

  /// Return "Espresso".
  description => "Espresso"

  /// Return the base price: $1.99.
  cost => 1.99

/// Decorator Pattern — HouseBlend (concrete component)
Beverage subclass: HouseBlend

  /// Return "House Blend".
  description => "House Blend"

  /// Return the base price: $0.89.
  cost => 0.89

/// Decorator Pattern — Milk (concrete decorator)
CondimentDecorator subclass: Milk

  /// Append ", Milk" to the wrapped beverage's description.
  description => "{self.beverage description}, Milk"

  /// Add $0.25 to the wrapped beverage's cost.
  cost => self.beverage cost + 0.25

/// Decorator Pattern — Sugar (concrete decorator)
CondimentDecorator subclass: Sugar

  /// Append ", Sugar" to the wrapped beverage's description.
  description => "{self.beverage description}, Sugar"

  /// Add $0.10 to the wrapped beverage's cost.
  cost => self.beverage cost + 0.1

/// Decorator Pattern — WhippedCream (concrete decorator)
CondimentDecorator subclass: WhippedCream

  /// Append ", Whipped Cream" to the wrapped beverage's description.
  description => "{self.beverage description}, Whipped Cream"

  /// Add $0.50 to the wrapped beverage's cost.
  cost => self.beverage cost + 0.5

/// Factory Method Pattern — Circle (concrete product)
Shape subclass: Circle
  field: radius = 1.0

  /// Create a circle with the given radius.
  class withRadius: r => self new: #{#radius => r}

  /// Return π * r².
  area => 3.14159 * self.radius * self.radius

  /// Return 2 * π * r.
  perimeter => 2.0 * 3.14159 * self.radius

  /// Return "Circle(r=<radius>)".
  describe => "Circle(r={self.radius})"

/// Factory Method Pattern — CircleFactory (concrete creator)
ShapeFactory subclass: CircleFactory
  field: radius = 1.0

  /// Create a factory configured to produce circles with the given radius.
  class withRadius: r => self new: #{#radius => r}

  /// Produce a Circle with this factory's configured radius.
  createShape => Circle withRadius: self.radius

/// Factory Method Pattern — Rectangle (concrete product)
Shape subclass: Rectangle
  field: width = 1.0
  field: height = 1.0

  /// Create a rectangle with the given width and height.
  class width: w height: h => self new: #{#width => w, #height => h}

  /// Return width * height.
  area => self.width * self.height

  /// Return 2 * (width + height).
  perimeter => 2.0 * (self.width + self.height)

  /// Return "Rectangle(<width>x<height>)".
  describe => "Rectangle({self.width}x{self.height})"

/// Factory Method Pattern — RectangleFactory (concrete creator)
ShapeFactory subclass: RectangleFactory
  field: width = 1.0
  field: height = 1.0

  /// Create a factory configured to produce rectangles with the given dimensions.
  class width: w height: h => self new: #{#width => w, #height => h}

  /// Produce a Rectangle with this factory's configured width and height.
  createShape => Rectangle width: self.width height: self.height

/// Factory Method Pattern — Shape (abstract product)
/// Intent: Define the common product interface implemented by concrete shapes
/// created by factory method creators.
Value subclass: Shape

  /// Return the area of this shape.
  area => self subclassResponsibility

  /// Return the perimeter (circumference) of this shape.
  perimeter => self subclassResponsibility

  /// Return a short human-readable label for this shape, e.g. "Circle(r=5.0)".
  describe => self subclassResponsibility

/// Factory Method Pattern — ShapeFactory (abstract creator)
/// Declares the factory method createShape and a template method describeShape
/// that uses it, demonstrating that the base class can call the factory method
/// without knowing which concrete product will be returned.
Value subclass: ShapeFactory

  /// Factory method — subclasses override this to return the appropriate Shape.
  createShape => self subclassResponsibility

  /// Template method — uses the factory method without knowing the concrete type.
  describeShape =>
    shape := self createShape
    "{shape describe}, area={shape area}"

/// Main entry point for gang_of_four.
/// Auto-runs via [run].entry in beamtalk.toml when you start `beamtalk repl`.
/// Or load manually: :load src/main.bt
Value subclass: Main

  class run => self new run

  run =>
    self traceCr: "Hello from gang_of_four!"
    self

/// Observer Pattern — EventBus (subject)
/// Intent: Define a one-to-many dependency so that when one object changes state,
/// all its dependents are notified automatically.
///
/// EventBus is an Actor (a BEAM process) so its subscriber list can be safely
/// shared and mutated across the system. Observers are any actors that respond
/// to receive:.
///
/// Usage:
///   bus     := EventBus spawn.
///   watcher := EventCollector spawn.
///   bus subscribe: watcher.
///   bus notify: "order.placed".
///   watcher eventCount   // => 1
Actor subclass: EventBus
  state: subscribers = #()

  /// Register an observer. It will receive all future notifications.
  subscribe: observer =>
    self.subscribers := self.subscribers add: observer
    self

  /// Deregister an observer. It will receive no further notifications.
  unsubscribe: observer =>
    self.subscribers := self.subscribers reject: [:s | s == observer]
    self

  /// Send event to every current subscriber by calling receive: on each.
  notify: event =>
    self.subscribers do: [:s | s receive: event]
    self

  /// Return the number of currently registered subscribers.
  subscriberCount => self.subscribers size

/// Observer Pattern — EventCollector (concrete observer)
/// Accumulates every event it receives. Useful as a test double and as a simple
/// audit log. Real observers would react to events (update UI, write to DB, etc.).
Actor subclass: EventCollector
  state: events = #()

  /// Called by EventBus notify: — appends the event to the internal log.
  receive: event =>
    self.events := self.events add: event
    self

  /// Return all received events in the order they arrived.
  events => self.events

  /// Return the number of events received so far.
  eventCount => self.events size

/// Singleton Pattern — AppLogger
/// Intent: Ensure a class has only one instance and provide a global point of access.
///
/// In Beamtalk/BEAM the idiomatic Singleton is a named actor process.
/// Spawn AppLogger once at application startup and share the actor reference.
/// Because the reference is a PID there is exactly one instance per node,
/// enforced by the BEAM scheduler — no synchronisation boilerplate needed.
///
/// Usage:
///   logger := AppLogger spawn.        // spawn once; share this reference
///   logger log: "app started".
///   logger log: "processing request".
///   logger size       // => 2
///   logger entries    // => #("app started", "processing request")
Actor subclass: AppLogger
  state: entries = #()

  /// Append a message to the log.
  log: message =>
    self.entries := self.entries add: message
    self

  /// Return all log entries in the order they were received.
  entries => self.entries

  /// Number of log entries recorded so far.
  size => self.entries size

  /// Remove all entries (e.g., between test runs).
  clear =>
    self.entries := #()
    self

/// Strategy Pattern — Sorter
/// Intent: Define a family of algorithms, encapsulate each one, and make them
/// interchangeable. The algorithm varies independently from the clients that use it.
///
/// Sorter holds a pluggable comparison block (the strategy) and applies it to sort
/// any list. Factory methods provide the most common orderings.
///
/// Usage:
///   asc := Sorter ascending.
///   asc sort: #(3, 1, 2).                             // => #(1, 2, 3)
///
///   desc := Sorter descending.
///   desc sort: #(3, 1, 2).                            // => #(3, 2, 1)
///
///   byLen := Sorter withStrategy: [:a :b | a length < b length].
///   byLen sort: #("banana", "fig", "apple").           // smallest first
Value subclass: Sorter
  field: strategy = nil

  /// Create a Sorter with a custom two-argument comparison block.
  /// The block returns true when its first argument should come before the second.
  class withStrategy: aBlock => self new: #{#strategy => aBlock}

  /// Convenience factory — ascending natural order.
  class ascending => self new: #{#strategy => [:a :b | a < b]}

  /// Convenience factory — descending natural order.
  class descending => self new: #{#strategy => [:a :b | a > b]}

  /// Sort aList using this Sorter's strategy. Returns the sorted list.
  sort: aList => aList sort: self.strategy

/// Template Method Pattern — CsvExporter
/// Formats rows as comma-separated values.
///
/// Usage:
///   rows := #(#("Alice", "30"), #("Bob", "25")).
///   CsvExporter new export: rows
///   // => "Alice,30\nBob,25\n"
DataExporter subclass: CsvExporter

  /// No header line for CSV output.
  header => ""

  /// No footer line for CSV output.
  footer => ""

  /// Format row as comma-separated cell values followed by a newline.
  formatRow: row =>
    (row inject: "" into: [:acc :cell |
      acc isEmpty ifTrue: [cell] ifFalse: ["{acc},{cell}"]
    ])
      ++ "\n"

/// Template Method Pattern — DataExporter (abstract base)
/// Intent: Define the skeleton of an algorithm in a base-class method, deferring
/// specific steps to subclasses. The overall structure stays fixed; only the
/// customisable steps change.
///
/// export: is the template method. It calls header, formatRow:, and footer in
/// order. Subclasses (CsvExporter, HtmlExporter) implement those three hooks.
Value subclass: DataExporter

  /// Template method — fixed algorithm skeleton.
  /// Do not override this in subclasses; override the hooks below instead.
  export: rows =>
    formatted := rows collect: [:row | self formatRow: row]
    self header ++ formatted join ++ self footer

  /// Hook: text placed before all rows. Subclasses must override.
  header => self subclassResponsibility

  /// Hook: text placed after all rows. Subclasses must override.
  footer => self subclassResponsibility

  /// Hook: format a single row (a List of cell strings). Subclasses must override.
  formatRow: _row => self subclassResponsibility

/// Template Method Pattern — HtmlExporter
/// Formats rows as an HTML table.
///
/// Usage:
///   rows := #(#("Alice", "30"), #("Bob", "25")).
///   HtmlExporter new export: rows
///   // => "<table>\n<tr><td>Alice</td><td>30</td></tr>\n...\n</table>\n"
DataExporter subclass: HtmlExporter

  /// Return the opening <table> tag.
  header => "<table>\n"

  /// Return the closing </table> tag.
  footer => "</table>\n"

  /// Wrap each cell in <td> and the whole row in <tr>.
  formatRow: row =>
    cells := row inject: "" into: [:acc :cell | acc ++ "<td>{cell}</td>"]
    "<tr>{cells}</tr>\n"

// AppSupervisor — root supervisor for the otp-tree application.
//
// Strategy #oneForOne: if a child crashes, only that child is restarted.
// EventLogger is a permanent worker — always restarted on crash.
// WorkerPool is a permanent DynamicSupervisor — always restarted, which
// also restarts any workers it was managing.
//
// This class is referenced in beamtalk.toml [application] supervisor,
// so `beamtalk run` starts it automatically as an OTP application.

Supervisor subclass: AppSupervisor

  class strategy -> Symbol => #oneForOne

  class children => #(EventLogger, WorkerPool)

// EventLogger — permanent actor that records events from across the system.
// Because its supervisionPolicy is #permanent, the supervisor always restarts
// it on crash.  Other actors can reach the running instance via the root
// supervisor: `(AppSupervisor current which: EventLogger) log: msg`.

Actor subclass: EventLogger
  state: events = #()

  class supervisionPolicy -> Symbol => #permanent

  log: message => self.events := self.events add: message

  events => self.events

  clear => self.events := #()

// TaskWorker — transient actor managed by WorkerPool.
// supervisionPolicy #transient: the supervisor restarts it only if it exits
// abnormally (crash).  A clean shutdown is not restarted.
//
// Error demo: sending `process: 0` raises a user_error back to the caller via
// self error:.  The actor process itself stays alive (the gen_server is not
// killed); the REPL walkthrough uses this to demonstrate fault isolation.

Actor subclass: TaskWorker
  state: jobCount = 0

  class supervisionPolicy -> Symbol => #transient

  process: value =>
    value =:= 0 ifTrue: [self error: "TaskWorker: refusing zero input"]
    self.jobCount := self.jobCount + 1
    value * 2

  jobCount => self.jobCount

// WorkerPool — DynamicSupervisor that manages TaskWorker children.
// Workers are started on demand at runtime via `pool startChild`.
// Each worker is supervised independently: a crash in one worker does not
// affect the others or the rest of the tree.

DynamicSupervisor(TaskWorker) subclass: WorkerPool

  class supervisionPolicy -> Symbol => #permanent

  class childClass => TaskWorker

/// SchemeEnv — mutable lexical environment for the Scheme interpreter.
///
/// Each environment frame is a live Beamtalk Actor holding a `Dictionary`
/// of name→value bindings and an optional parent reference. Because actors
/// own their state, `define:value:` persists across calls without threading
/// an updated environment through every expression — a natural fit for
/// Scheme's mutable top-level environment.
///
/// Environments form a chain: global (built-ins) ← top-level defines
/// ← lambda frame ← nested frames. `lookup:` walks the chain automatically.
///
/// ## Examples
/// ```beamtalk
/// env := SchemeEnv spawnWith: #{#bindings => #{}, #parent => nil}
/// env define: "x" value: 42
/// env lookup: "x"    // => 42
/// ```
Actor subclass: SchemeEnv
  state: bindings = #{}
  state: parent = nil

  /// Look up `name` in this frame, then walk parent frames until found.
  /// Raises an error if the name is unbound in the entire chain, or if the
  /// parent chain exceeds 1000 frames (cycle guard).
  ///
  /// ## Examples
  /// ```beamtalk
  /// env lookup: "x"    // => 42 (if x was defined)
  /// env lookup: "z"    // raises "Unbound variable: z"
  /// ```
  lookup: name => self lookup: name depth: 0

  lookup: name depth: depth =>
    (depth > 1000) ifTrue: [
      ^self error: "Environment chain exceeded maximum depth (cycle detected?)"
    ]
    (self.bindings includesKey: name) ifTrue: [^self.bindings at: name]
    self.parent notNil ifTrue: [^(self.parent lookup: name depth: depth + 1)]
    self error: "Unbound variable: " ++ name

  /// Bind or rebind `name` to `val` in this frame.
  ///
  /// ## Examples
  /// ```beamtalk
  /// env define: "x" value: 10
  /// env lookup: "x"    // => 10
  /// ```
  define: name value: val =>
    self.bindings := self.bindings at: name put: val
    nil

  /// Set this frame's parent environment (used during construction).
  /// Raises an error if `p` is `self` to prevent self-parent loops.
  setParent: p =>
    (p =:= self) ifTrue: [
      ^self error: "Cycle detected: environment cannot be its own parent"
    ]
    self.parent := p

  /// Create a child environment that binds each name in `params` to the
  /// corresponding value in `vals`, with `self` as parent. Used by lambda
  /// application to build a new call frame.
  ///
  /// ## Examples
  /// ```beamtalk
  /// child := env extend: #("x", "y") values: #(3, 4)
  /// child lookup: "x"   // => 3
  /// child lookup: "y"   // => 4
  /// ```
  extend: params values: vals =>
    (params size =:= vals size)
      ifFalse: [
        ^self
          error: "Arity mismatch: expected "
            ++ params size printString
            ++ ", got "
            ++ vals size printString
      ]
    newBindings := (params zip: vals) inject: #{} into: [:d :pair |
      d at: pair first put: pair last
    ]
    SchemeEnv spawnWith: #{#bindings => newBindings, #parent => self}

/// SchemeEval — the metacircular evaluator.
///
/// `eval:in:` dispatches on expression type following the classic SICP
/// eval/apply loop:
///
/// - **Self-evaluating** — integers, booleans, strings, nil are returned as-is.
/// - **Symbols** — looked up in the environment via `SchemeEnv>>lookup:`.
/// - **Lists** — special forms or function application.
///
/// Special forms: `quote`, `define`, `lambda`, `if`, `cond`, `let`, `and`, `or`.
///
/// Built-in procedures are `Block` values stored directly in the environment
/// dictionary, so no separate primitive dispatch table is needed.
///
/// ## Examples
/// ```beamtalk
/// reader := SchemeReader new
/// eval   := SchemeEval new
/// env    := eval defaultEnv
///
/// eval eval: (reader read: "(* 6 7)") in: env      // => 42
/// eval eval: (reader read: "(define x 10)") in: env  // => nil
/// eval eval: (reader read: "x") in: env            // => 10
/// ```
Value subclass: SchemeEval

  /// Build a fresh `SchemeEnv` pre-loaded with standard arithmetic and
  /// list primitives: `+`, `-`, `*`, `/`, `=`, `<`, `>`, `<=`, `>=`,
  /// `car`, `cdr`, `cons`, `list`, `not`, `null?`.
  ///
  /// Each primitive is a `Block` that receives the full evaluated argument
  /// list and returns the result.
  ///
  /// ## Examples
  /// ```beamtalk
  /// env := SchemeEval new defaultEnv
  /// (env lookup: "+")   // => a Block
  /// ```
  defaultEnv =>
    SchemeEnv
      spawnWith: #{
        #bindings => #{
          "+" => [:args | (args at: 1) + (args at: 2)],
          "-" => [:args | (args at: 1) - (args at: 2)],
          "*" => [:args | (args at: 1) * (args at: 2)],
          "/" => [:args | (args at: 1) div: (args at: 2)],
          "=" => [:args | (args at: 1) =:= (args at: 2)],
          "<" => [:args | (args at: 1) < (args at: 2)],
          ">" => [:args | (args at: 1) > (args at: 2)],
          "<=" => [:args | (args at: 1) <= (args at: 2)],
          ">=" => [:args | (args at: 1) >= (args at: 2)],
          "car" => [:args | (args at: 1) first],
          "cdr" => [:args | (args at: 1) rest],
          "cons" => [:args | (#() add: (args at: 1)) ++ (args at: 2)],
          "list" => [:args | args],
          "not" => [:args | (args at: 1) not],
          "null?" => [:args |
            v := args at: 1
            v isNil or: [v class =:= List and: [v isEmpty]]
          ]
        },
        #parent => nil
      }

  /// Evaluate `expr` in `env` and return the result.
  ///
  /// Dispatches on expression type: self-evaluating atoms are returned
  /// immediately; symbols trigger an environment lookup; lists are processed
  /// as special forms or function application.
  ///
  /// ## Examples
  /// ```beamtalk
  /// ev  := SchemeEval new
  /// env := ev defaultEnv
  /// ev eval: 42 in: env                          // => 42
  /// ev eval: (SchemeSymbol withName: "+") in: env  // => a Block
  /// ```
  eval: expr in: env =>
    // Self-evaluating atomic types
    (expr isNil or: [
      #(Integer, True, False, String) includes: expr class
    ]) ifTrue: [^expr]

    // Symbol: look up the name in the environment
    (expr class =:= SchemeSymbol) ifTrue: [^(env lookup: expr name)]

    // Must be a list — special form or function application
    (expr class =:= List) ifFalse: [^self error: "Unknown expression type"]
    expr isEmpty ifTrue: [^#()]

    head := expr first
    tail := expr rest

    // Special form dispatch (symbols) or function application
    (head class =:= SchemeSymbol)
      ifTrue: [
        ^self
          evalSpecialOrApply: head
          tail: tail
          in: env
      ]
    self
      evalApply: head
      tail: tail
      in: env

  /// Dispatch `head` as a special form or function application.
  /// Called when `head` is a `SchemeSymbol`; `tail` is the rest of the list.
  evalSpecialOrApply: head tail: tail in: env =>
    sym := head name
    sym match: [
      // (quote expr) — return unevaluated
      "quote" -> tail first;

      // (define name expr) — bind name in the current environment
      "define" -> [
        varName := (tail at: 1) name
        defVal := self eval: (tail at: 2) in: env
        env define: varName value: defVal
        nil
      ] value;

      // (lambda (params...) body) — create a closure
      "lambda" -> [
        params := (tail at: 1) collect: [:p | p name]
        SchemeLambda
          withParams: params
          body: (tail at: 2)
          env: env
      ] value;

      // (if test then else?) — conditional branch
      "if" -> [
        condVal := self eval: (tail at: 1) in: env
        isFalsy := self isFalsy: condVal
        isFalsy ifTrue: [
          (tail size > 2) ifTrue: [
            self eval: (tail at: 3) in: env
          ] ifFalse: [nil]
        ] ifFalse: [self eval: (tail at: 2) in: env]
      ] value;

      // (cond (test expr) ... (else expr))
      "cond" -> self evalCond: tail in: env;

      // (and expr ...) — short-circuit conjunction
      "and" -> self evalAnd: tail in: env;

      // (or expr ...) — short-circuit disjunction
      "or" -> self evalOr: tail in: env;

      // (let ((var expr) ...) body) — local bindings
      "let" -> [
        binds := tail at: 1
        letBody := tail at: 2
        params := binds collect: [:b | (b at: 1) name]
        argVals := binds collect: [:b | self eval: (b at: 2) in: env]
        childEnv := env extend: params values: argVals
        self eval: letBody in: childEnv
      ] value;

      // Not a special form — evaluate head as a function and apply
      _ -> [
        self
          evalApply: head
          tail: tail
          in: env
      ] value
    ]

  /// Evaluate `head` as a procedure and apply it to the evaluated `tail` args.
  evalApply: head tail: tail in: env =>
    func := self eval: head in: env
    evalArgs := tail collect: [:a | self eval: a in: env]
    self
      apply: func
      args: evalArgs
      in: env

  /// Apply `func` to the evaluated argument list `args`.
  ///
  /// - `SchemeLambda` — extends the closure env with parameter bindings
  ///   and recurses into the body.
  /// - `Block` — calls the block with `args` as a single list argument
  ///   (the convention for all built-in primitives).
  /// - Anything else — raises `"Not a procedure: <value>"`.
  ///
  /// ## Examples
  /// ```beamtalk
  /// ev apply: [:a | (a at: 1) + (a at: 2)] args: #(3, 4) in: env   // => 7
  /// ```
  apply: func args: args in: _env =>
    (func class =:= SchemeLambda)
      ifTrue: [
        childEnv := func closureEnv extend: func params values: args
        ^self eval: func body in: childEnv
      ]
    (func class =:= Block) ifFalse: [
      ^self error: "Not a procedure: " ++ func printString
    ]
    // Built-in: block takes the full args list as its single argument
    func value: args

  /// Return true if `val` is Scheme-falsy (i.e. `false` or `nil`).
  isFalsy: val => val == false or: [val isNil]

  /// Evaluate `cond` clauses in order; return the first truthy branch.
  /// An `else` clause always matches. Returns `nil` if all tests fail.
  evalCond: clauses in: env =>
    clauses isEmpty ifTrue: [^nil]
    clause := clauses first
    ((clause first class =:= SchemeSymbol) and: [
      clause first name =:= "else"
    ]) ifTrue: [^self eval: clause last in: env]
    condVal := self eval: clause first in: env
    (self isFalsy: condVal) ifTrue: [
      self evalCond: clauses rest in: env
    ] ifFalse: [self eval: clause last in: env]

  /// Evaluate `(and ...)` — return `false` on the first falsy value,
  /// otherwise return the last value.
  evalAnd: exprs in: env =>
    exprs isEmpty ifTrue: [^true]
    val := self eval: exprs first in: env
    (self isFalsy: val) ifTrue: [^false]
    exprs size =:= 1 ifTrue: [^val]
    self evalAnd: exprs rest in: env

  /// Evaluate `(or ...)` — return the first truthy value,
  /// or `false` if all expressions are falsy.
  evalOr: exprs in: env =>
    exprs isEmpty ifTrue: [^false]
    val := self eval: exprs first in: env
    (self isFalsy: val) ifFalse: [^val]
    self evalOr: exprs rest in: env

/// SchemeLambda — a user-defined Scheme procedure (closure).
///
/// Captures the parameter list, unevaluated body AST, and the lexical
/// environment at the point of definition. Application is handled by
/// `SchemeEval>>apply:args:in:`, which extends the closure env with
/// parameter bindings and recurses into the body.
///
/// ## Examples
/// ```beamtalk
/// lam := SchemeLambda withParams: #("x") body: bodyExpr env: env
/// lam params       // => #("x")
/// lam body         // => bodyExpr
/// lam closureEnv   // => the SchemeEnv actor
/// ```
Value subclass: SchemeLambda
  field: params = #()  // List of parameter name strings
  field: body = nil  // Unevaluated body expression (AST)
  field: closureEnv = nil  // SchemeEnv actor at point of definition

  /// Create a new lambda capturing `p` as parameter names, `b` as the body
  /// AST, and `e` as the enclosing environment.
  ///
  /// ## Examples
  /// ```beamtalk
  /// SchemeLambda withParams: #("x") body: ast env: env
  /// ```
  class withParams: p body: b env: e =>
    SchemeLambda new: #{#params => p, #body => b, #closureEnv => e}

/// SchemePrinter — converts Beamtalk values back to Scheme notation.
///
/// Handles every type produced by `SchemeEval`: integers, booleans, strings,
/// nil, `SchemeSymbol`, `SchemeLambda`, and `List`. The main entry point is
/// `print:`, which dispatches on the value's class.
///
/// ## Examples
/// ```beamtalk
/// printer := SchemePrinter new
/// printer print: 42          // => "42"
/// printer print: true        // => "#t"
/// printer print: false       // => "#f"
/// printer print: nil         // => "()"
/// printer print: #(1, 2, 3)    // => "(1 2 3)"
/// ```
Value subclass: SchemePrinter

  /// Convert `val` to its Scheme string representation.
  ///
  /// Dispatches on `val class`: nil → `"()"`, booleans → `"#t"`/`"#f"`,
  /// integers → decimal string, strings → double-quoted, symbols → name,
  /// lambdas → `"#<lambda>"`, lists → `"(elem ...)"`.
  ///
  /// ## Examples
  /// ```beamtalk
  /// SchemePrinter new print: 0          // => "0"
  /// SchemePrinter new print: "hi"       // => "\"hi\""
  /// SchemePrinter new print: nil        // => "()"
  /// ```
  print: val =>
    val isNil ifTrue: [^"()"]
    (val class =:= True) ifTrue: [^"#t"]
    (val class =:= False) ifTrue: [^"#f"]
    (val class =:= Integer) ifTrue: [^val printString]
    (val class =:= String) ifTrue: [^"""" ++ val ++ """"]
    (val class =:= SchemeSymbol) ifTrue: [^val name]
    (val class =:= SchemeLambda) ifTrue: [^"#<lambda>"]
    (val class =:= List) ifTrue: [^self printList: val]
    "#<unknown>"

  /// Format a list as a Scheme-style `(elem ...)` string.
  ///
  /// ## Examples
  /// ```beamtalk
  /// SchemePrinter new printList: #()        // => "()"
  /// SchemePrinter new printList: #(1, 2, 3)   // => "(1 2 3)"
  /// ```
  printList: lst =>
    lst isEmpty ifTrue: [^"()"]
    inner := self printElems: lst
    "(" ++ inner ++ ")"

  /// Recursively format list elements separated by spaces.
  printElems: lst =>
    lst size =:= 1 ifTrue: [^self print: lst first]
    (self print: lst first) ++ " " ++ (self printElems: lst rest)

/// SchemeReader — tokenises and parses s-expression strings into Beamtalk values.
///
/// Uses a functional char-list approach: each internal parse method receives a
/// List of single-character String values (from `String>>asList`) and returns a
/// 2-element `#(parsedValue, remainingChars)` pair. The public `read:` entry
/// point extracts just the value.
///
/// Supported syntax:
/// - **atoms** — symbols, integers, booleans (`#t` / `#f`), strings (`"..."`)
/// - **lists** — `(elem ...)` including nested lists
///
/// String escaping: a doubled delimiter `""` produces a literal `"` character.
///
/// ## Examples
/// ```beamtalk
/// reader := SchemeReader new
/// reader read: "(+ 1 2)"    // => #(SchemeSymbol(+), 1, 2)
/// reader read: "42"         // => 42
/// reader read: "#t"         // => true
/// reader read: "()"         // => #()
/// ```
Value subclass: SchemeReader

  /// Parse a Scheme expression string and return its AST value.
  ///
  /// ## Examples
  /// ```beamtalk
  /// SchemeReader new read: "(* 6 7)"   // => #(SchemeSymbol(*), 6, 7)
  /// SchemeReader new read: "hello"     // => SchemeSymbol("hello")
  /// ```
  read: str =>
    chars := str asList
    pair := self parseExpr: (self dropWs: chars)
    rest := self dropWs: pair last
    rest isEmpty ifFalse: [^self error: "Unexpected trailing input"]
    pair first

  /// Return true if `ch` is a whitespace character (space, newline, tab, carriage return).
  isWs: ch => #(" ", "\n", "\t", "\r") includes: ch

  /// Drop leading whitespace characters from a char list.
  dropWs: chars =>
    chars isEmpty ifTrue: [^chars]
    (self isWs: chars first) ifFalse: [^chars]
    self dropWs: chars rest

  /// Wrap `val` and `chars` into a 2-element `#(val, remainingChars)` pair.
  pairOf: val rest: chars => (#() add: val) add: chars

  /// Return true if `ch` is a token delimiter (whitespace, `(`, or `)`).
  isDelim: ch => (self isWs: ch) or: [#("(", ")") includes: ch]

  /// Dispatch to the appropriate sub-parser based on the leading character.
  ///
  /// - `(` → list
  /// - `#` → boolean
  /// - digit → integer
  /// - `"` → string
  /// - anything else → symbol
  parseExpr: chars =>
    chars isEmpty ifTrue: [^self error: "Unexpected end of input"]
    ch := chars first
    (ch =:= "(") ifTrue: [^self parseListElems: chars rest]
    (ch =:= "#") ifTrue: [^self parseBool: chars rest]
    ch isDigit ifTrue: [^self parseNum: chars acc: ""]
    (ch =:= """") ifTrue: [^self parseString: chars rest acc: ""]
    self parseSym: chars acc: ""

  /// Parse list elements after the opening `(` has been consumed.
  /// Recursively parses elements until `)` is reached.
  parseListElems: chars =>
    trimmed := self dropWs: chars
    trimmed isEmpty ifTrue: [^self error: "Missing ')'"]
    (trimmed first =:= ")") ifTrue: [^self pairOf: #() rest: trimmed rest]
    headPair := self parseExpr: trimmed
    head := headPair first
    tailPair := self parseListElems: (self dropWs: headPair last)
    tail := tailPair first
    self pairOf: ((#() add: head) ++ tail) rest: tailPair last

  /// Parse `#t` or `#f`; `chars` is positioned after the `#`.
  ///
  /// ## Examples
  /// ```beamtalk
  /// SchemeReader new read: "#t"   // => true
  /// SchemeReader new read: "#f"   // => false
  /// ```
  parseBool: chars =>
    chars isEmpty ifTrue: [^self error: "Unexpected '#'"]
    (chars first =:= "t") ifTrue: [^self pairOf: true rest: chars rest]
    (chars first =:= "f") ifTrue: [^self pairOf: false rest: chars rest]
    self error: "Unknown # token"

  /// Parse an integer by accumulating digit characters until a delimiter.
  ///
  /// ## Examples
  /// ```beamtalk
  /// SchemeReader new read: "42"    // => 42
  /// ```
  parseNum: chars acc: acc =>
    (chars isEmpty or: [
      self isDelim: chars first
    ]) ifTrue: [^self pairOf: acc asInteger rest: chars]
    self parseNum: chars rest acc: acc ++ chars first

  /// Parse a string literal; `chars` is positioned after the opening `"`.
  /// A doubled delimiter `""` represents a single literal `"` character.
  ///
  /// ## Examples
  /// ```beamtalk
  /// SchemeReader new read: """hello"""     // => "hello"
  /// ```
  parseString: chars acc: acc =>
    chars isEmpty ifTrue: [^self error: "Unterminated string literal"]
    (chars first =:= """")
      ifTrue: [
        (chars rest isEmpty not and: [
          chars rest first =:= """"
        ]) ifTrue: [^self parseString: chars rest rest acc: acc ++ """"]
        ^self pairOf: acc rest: chars rest
      ]
    self parseString: chars rest acc: acc ++ chars first

  /// Parse a symbol by accumulating non-delimiter characters.
  ///
  /// ## Examples
  /// ```beamtalk
  /// SchemeReader new read: "define"   // => SchemeSymbol("define")
  /// SchemeReader new read: "+"        // => SchemeSymbol("+")
  /// ```
  parseSym: chars acc: acc =>
    (chars isEmpty or: [
      self isDelim: chars first
    ]) ifTrue: [^self pairOf: (SchemeSymbol withName: acc) rest: chars]
    self parseSym: chars rest acc: acc ++ chars first

/// SchemeSymbol — a Scheme symbol (identifier), distinct from Beamtalk strings.
///
/// Using a dedicated class keeps symbols separate from string literals so the
/// evaluator can distinguish "look this name up in the environment" from
/// "return this string value as-is". Symbols with the same name are equal.
///
/// ## Examples
/// ```beamtalk
/// sym := SchemeSymbol withName: "define"
/// sym name           // => "define"
/// sym == (SchemeSymbol withName: "define")  // => true
/// sym == (SchemeSymbol withName: "lambda")  // => false
/// ```
Value subclass: SchemeSymbol
  field: symName = ""

  /// Create a new symbol with the given name string.
  ///
  /// ## Examples
  /// ```beamtalk
  /// SchemeSymbol withName: "car"   // => a SchemeSymbol
  /// ```
  class withName: n => SchemeSymbol new: #{#symName => n}

  /// Return the symbol name string.
  ///
  /// ## Examples
  /// ```beamtalk
  /// (SchemeSymbol withName: "cons") name   // => "cons"
  /// ```
  name => self.symName

  /// Return the symbol name as a string (same as `name`).
  ///
  /// ## Examples
  /// ```beamtalk
  /// (SchemeSymbol withName: "cons") printString   // => "cons"
  /// ```
  printString => self.symName

