// BT-172, BT-397: Tests actor lifecycle — isAlive, stop, idempotent stop,
// and error behaviour when sending to a stopped actor

TestCase subclass: ActorLifecycleTest

  testIsAliveAndStop =>
    counter := Counter spawn
    // isAlive returns true for a running actor
    self assert: counter isAlive
    // Actor still works after isAlive check
    self assert: counter increment equals: 1
    // isAlive still true after message processing
    self assert: counter isAlive
    // Stop the actor gracefully
    self assert: counter stop equals: #ok
    // Stopping an already-stopped actor is idempotent
    self assert: counter stop equals: #ok
    // isAlive returns false after stop
    self deny: counter isAlive
    // Sending a message to a stopped actor raises an error
    self should: [counter increment] raise: #actor_dead

  testNonMapArgumentToSpawnwith =>
    // not silently fall back to spawn/0
    self should: [Counter spawnWith: 42] raise: #type_error
    // Passing a non-Dictionary argument to spawnWith: should raise type_error,
    self should: [Counter spawnWith: "hello"] raise: #type_error
    self should: [Counter spawnWith: true] raise: #type_error

  testSpawnwithWithBareIdentifierKeys =>
    // Bare identifier keys in map literals work as implicit symbols (formatter normalizes to #symbol form)
    c3 := Counter spawnWith: #{#value => 10}
    self assert: c3 getValue equals: 10
    self assert: c3 increment equals: 11

  testPrintstringActorInstanceAndClassObject =>
    // Actor instance printString returns "a ClassName"
    c2 := Counter spawn
    self assert: c2 printString equals: "a Counter"
    // Class object printString returns class name
    self assert: Counter printString equals: "Counter"

  testNewRaisesInstantiationError =>
    // Counter new raises InstantiationError (BT-1056: class-side new)
    self should: [Counter new] raise: #instantiation_error
    // Counter new: raises InstantiationError (BT-1056: class-side new:)
    self should: [Counter new: #{}] raise: #instantiation_error

  testNewIsCatchableAsInstantiationError =>
    // Counter new is catchable via on: InstantiationError do: (BT-1056)
    result := [Counter new] on: InstantiationError do: [:_e | #caught]
    self assert: result equals: #caught

