    self assert: ([:x :y | x + y] valueWithArguments: #(3, 4)) equals: 7
    // Zero-arg block
    self assert: ([42] valueWithArguments: #()) equals: 42
    // Single-arg block
    self assert: ([:x | x * 2] valueWithArguments: #(5)) equals: 10

  testBlockArity =>
