// Stdlib tests for Collection abstract superclass (BT-505)

TestCase subclass: CollectionProtocolTest

  testSetSharedCollectionProtocolInheritedFromCollection =>
    // Set isEmpty
    self assert: Set new isEmpty
    self deny: (Set new add: 1) isEmpty
    // Set isNotEmpty
    self assert: (Set new add: 1) isNotEmpty
    self deny: Set new isNotEmpty
    // Set includes:
    self assert: ((Set new add: 1) includes: 1)
    self deny: ((Set new add: 1) includes: 2)
    // Set collect: (inherited from Collection)
    self assert: (((Set new add: 1) add: 2) collect: [:x |
      x * 10
    ]) size equals: 2
    // Set select: (inherited from Collection)
    self assert: ((((Set new add: 1) add: 2) add: 3) select: [:x |
      x > 1
    ]) size equals: 2
    // Set reject: (inherited from Collection)
    self assert: ((((Set new add: 1) add: 2) add: 3) reject: [:x |
      x > 2
    ]) size equals: 2
    // Set inject:into: (inherited from Collection)
    self assert: ((((Set new add: 1) add: 2) add: 3) inject: 0 into: [:sum :x |
      sum + x
    ]) equals: 6
    // Set detect: (inherited from Collection)
    self assert: ((((Set new add: 1) add: 2) add: 3) detect: [:x |
      x > 1
    ]) notNil
    // Set detect:ifNone: (inherited from Collection)
    self assert: ((Set new add: 1) detect: [:x | x > 5] ifNone: [0]) equals: 0
    // Set anySatisfy: (inherited from Collection)
    self assert: ((((Set new add: 1) add: 2) add: 3) anySatisfy: [:x | x > 2])
    self deny: (((Set new add: 1) add: 2) anySatisfy: [:x | x > 5])
    // Set allSatisfy: (inherited from Collection)
    self assert: ((((Set new add: 1) add: 2) add: 3) allSatisfy: [:x | x > 0])
    self deny: ((((Set new add: 1) add: 2) add: 3) allSatisfy: [:x | x > 2])

  testDictionaryCollectionProtocol =>
    // Dictionary isEmpty (inherited from Collection via size)
    self assert: #{} isEmpty
    self deny: #{#a => 1} isEmpty
    // Dictionary do: iterates over values
    self assert: (#{#a => 10, #b => 20} do: [:v | v + 1]) equals: nil
    // Dictionary includes: checks values
    self assert: (#{#a => 1, #b => 2} includes: 1)
    self deny: (#{#a => 1, #b => 2} includes: 99)
    // Dictionary collect: (inherited from Collection via do:)
    self assert: (#{#a => 1, #b => 2} collect: [:v | v * 10]) size equals: 2
    // Dictionary select: (inherited from Collection via do:)
    self assert: (#{
      #a => 1,
      #b => 2,
      #c => 3
    } select: [:v | v > 1]) size equals: 2
    // Dictionary inject:into: (inherited from Collection via do:)
    self assert: (#{
      #a => 1,
      #b => 2,
      #c => 3
    } inject: 0 into: [:sum :v | sum + v]) equals: 6
    // Dictionary detect: (inherited from Collection via do:)
    self assert: (#{#a => 1, #b => 5, #c => 3} detect: [:v | v > 4]) equals: 5
    // Dictionary detect:ifNone:
    self assert: (#{#a => 1} detect: [:v | v > 10] ifNone: [0]) equals: 0
    // Dictionary anySatisfy: (inherited from Collection)
    self assert: (#{#a => 1, #b => 5} anySatisfy: [:v | v > 3])
    self deny: (#{#a => 1, #b => 2} anySatisfy: [:v | v > 5])
    // Dictionary allSatisfy: (inherited from Collection)
    self assert: (#{#a => 2, #b => 4} allSatisfy: [:v | v isEven])
    self deny: (#{#a => 1, #b => 2} allSatisfy: [:v | v isEven])

  testTupleCollectionProtocol =>
    // Tuple empty creation
    self assert: Tuple new class equals: Tuple

  testClassHierarchyVerification =>
    // Verify superclass chain
    self assert: #(1, 2, 3) class equals: List
    self assert: Set new class equals: Set
    self assert: #{} class equals: Dictionary

// BT-44, BT-75: Tests List methods — creation, literals, mutation (add:, remove:),
// iteration (do:, collect:, select:, reject:, inject:into:), sort, advanced
// methods (zip:, groupBy:, partition:), and new methods (++, from:to:, indexOf:,
// eachWithIndex:, intersperse:)

TestCase subclass: CollectionsTest

  testCreation =>
    self assert: List new equals: #()
    self assert: (List new) size equals: 0
    self assert: (List new) class equals: List
    // List new: accepts a List (convenience alias for withAll:)
    self assert: (List new: #(1, 2, 3)) equals: #(1, 2, 3)

  testTier1EssentialMethods =>
    // --- last ---
    self assert: #(1, 2, 3) last equals: 3
    self assert: #(42) last equals: 42
    // --- at: ---
    self assert: (#(10, 20, 30) at: 1) equals: 10
    self assert: (#(10, 20, 30) at: 3) equals: 30
    // --- includes: ---
    self assert: (#(1, 2, 3) includes: 2)
    self deny: (#(1, 2, 3) includes: 5)
    self deny: (#() includes: 1)
    // --- sort ---
    self assert: #(3, 1, 2) sort equals: #(1, 2, 3)
    self assert: #() sort equals: #()
    // --- reversed ---
    self assert: #(1, 2, 3) reversed equals: #(3, 2, 1)
    self assert: #() reversed equals: #()
    // --- detect: ---
    self assert: (#(1, 2, 3, 4) detect: [:x | x > 2]) equals: 3
    // --- detect:ifNone: ---
    self assert: (#(1, 2, 3) detect: [:x | x > 10] ifNone: [0]) equals: 0
    self assert: (#(1, 2, 3) detect: [:x | x > 1] ifNone: [0]) equals: 2

  testTier2FunctionalMethods =>
    // --- take: ---
    self assert: (#(1, 2, 3, 4, 5) take: 3) equals: #(1, 2, 3)
    self assert: (#(1, 2) take: 5) equals: #(1, 2)
    // --- drop: ---
    self assert: (#(1, 2, 3, 4, 5) drop: 2) equals: #(3, 4, 5)
    self assert: (#(1, 2) drop: 5) equals: #()
    // --- flatten ---
    self assert: #(#(1, 2), #(3, 4)) flatten equals: #(1, 2, 3, 4)
    // --- flatMap: ---
    self assert: (#(1, 2, 3) flatMap: [:x |
      #(x, (x * 10))
    ]) equals: #(1, 10, 2, 20, 3, 30)
    // --- count: ---
    self assert: (#(1, 2, 3, 4, 5) count: [:x | x > 2]) equals: 3
    // --- anySatisfy: ---
    self assert: (#(1, 2, 3) anySatisfy: [:x | x > 2])
    self deny: (#(1, 2, 3) anySatisfy: [:x | x > 5])
    // --- allSatisfy: ---
    self assert: (#(1, 2, 3) allSatisfy: [:x | x > 0])
    self deny: (#(1, 2, 3) allSatisfy: [:x | x > 1])

  testAddFirst =>
    // --- addFirst: (O(1) cons prepend) ---
    self assert: (#(2, 3) addFirst: 1) equals: #(1, 2, 3)
    self assert: (#() addFirst: "x") equals: #("x")

  testTier3AdvancedMethods =>
    // --- unique ---
    self assert: #(3, 1, 2, 1, 3) unique equals: #(1, 2, 3)
    // --- takeWhile: ---
    self assert: (#(1, 2, 3, 4, 5) takeWhile: [:x | x < 4]) equals: #(1, 2, 3)
    // --- dropWhile: ---
    self assert: (#(1, 2, 3, 4, 5) dropWhile: [:x | x < 3]) equals: #(3, 4, 5)
    // --- intersperse: ---
    self assert: (#(1, 2, 3) intersperse: 0) equals: #(1, 0, 2, 0, 3)
    self assert: (#() intersperse: 0) equals: #()
    // --- add: ---
    self assert: (#(1, 2, 3) add: 4) equals: #(1, 2, 3, 4)
    self assert: (#() add: 1) equals: #(1)

  testAdvancedMethods =>
    // --- zip: ---
    zipped := #(1, 2, 3) zip: #(4, 5, 6)
    self assert: zipped size equals: 3
    pair := zipped first
    self assert: pair first equals: 1
    self assert: pair last equals: 4
    // --- groupBy: ---
    grouped := #(1, 2, 3, 4, 5, 6) groupBy: [:x | x isEven]
    self assert: grouped size equals: 2
    // --- partition: ---
    partitioned := #(1, 2, 3, 4) partition: [:x | x > 2]
    self assert: partitioned size equals: 2
    // --- sort: (with comparator) ---
    self assert: (#(3, 1, 2) sort: [:a :b | a >= b]) equals: #(3, 2, 1)

  testFromToAndIndexOf =>
    // --- ++ (concatenation) ---
    self assert: (#(1, 2) ++ #(3, 4)) equals: #(1, 2, 3, 4)
    self assert: (#() ++ #(1, 2)) equals: #(1, 2)
    self assert: (#(1, 2) ++ #()) equals: #(1, 2)
    self assert: (#() ++ #()) equals: #()
    // --- from:to: (subsequence, 1-based inclusive) ---
    self assert: (#(1, 2, 3, 4, 5) from: 2 to: 4) equals: #(2, 3, 4)
    // Wildcard for single-element result (Erlang printable_list ambiguity with small integers)
    self assert: (#(1, 2, 3, 4, 5) from: 1 to: 1) equals: #(1)
    // Two-element subsequence verifies inclusive bounds
    self assert: (#(1, 2, 3, 4, 5) from: 1 to: 2) equals: #(1, 2)
    self assert: (#(1, 2, 3, 4, 5) from: 1 to: 5) equals: #(1, 2, 3, 4, 5)
    self assert: (#(1, 2, 3) from: 3 to: 2) equals: #()
    // from:to: beyond list end returns available elements
    self assert: (#(1, 2, 3) from: 2 to: 10) equals: #(2, 3)
    // --- indexOf: (1-based, nil if not found) ---
    self assert: (#(10, 20, 30) indexOf: 20) equals: 2
    self assert: (#(10, 20, 30) indexOf: 10) equals: 1
    self assert: (#(10, 20, 30) indexOf: 30) equals: 3
    self assert: (#(10, 20, 30) indexOf: 99) equals: nil
    // indexOf: returns first match when duplicates exist
    self assert: (#(1, 2, 3, 2) indexOf: 2) equals: 2
    self assert: (#() indexOf: 1) equals: nil
    // eachWithIndex: returns nil after iterating
    self assert: (#(10, 20, 30) eachWithIndex: [:elem :idx |
      elem + idx
    ]) equals: nil
    // Verify eachWithIndex: iterates (empty list is a no-op)
    self assert: (#() eachWithIndex: [:elem :idx | elem]) equals: nil
    // The block receives (elem, idx) — verify it doesn't error with 2-arg block:
    self assert: (#(100, 200, 300) eachWithIndex: [:elem :idx |
      elem + idx
    ]) equals: nil
    // --- ++ with variables ---
    a := #(1, 2, 3)
    self assert: a equals: #(1, 2, 3)
    // Direct index assertion not possible in E2E since blocks can't accumulate results
    self assert: (a ++ #(4, 5)) equals: #(1, 2, 3, 4, 5)

  testJoin =>
    // BT-895: join and join: caused infinite dispatch loop
    // --- join (no separator) ---
    self assert: #("hello", "world") join equals: "helloworld"
    self assert: #("a", "b", "c") join equals: "abc"
    self assert: #() join equals: ""
    // --- join: (with separator) ---
    self assert: (#("a", "b", "c") join: ", ") equals: "a, b, c"
    self assert: (#("hello", "world") join: " ") equals: "hello world"
    self assert: (#("x") join: ", ") equals: "x"
    self assert: (#() join: ", ") equals: ""

// BT-1477: Tests state threading composition between conditional blocks
// and HOF blocks — verifies that self.field := mutations persist correctly
// in all nested combinations

TestCase subclass: ConditionalHofStateTest

  // --- ifTrue: wrapping do: ---
  testIfTrueDoIncrementTrue =>
    a := ConditionalHofStateActor spawn
    // flag=true, list=#(1, 2, 3) => count = 0 + 1 + 2 + 3 = 6
    self assert: (a conditionalDoIncrement: true with: #(1, 2, 3)) equals: 6

  testIfTrueDoIncrementFalse =>
    a := ConditionalHofStateActor spawn
    // flag=false => count unchanged = 0
    self assert: (a conditionalDoIncrement: false with: #(1, 2, 3)) equals: 0

  testIfTrueDoIncrementAccumulates =>
    a := ConditionalHofStateActor spawn
    a conditionalDoIncrement: true with: #(1, 2, 3)
    // Second call: count = 6 + 4 + 5 = 15
    self assert: (a conditionalDoIncrement: true with: #(4, 5)) equals: 15

  // --- ifFalse: wrapping do: ---
  testIfFalseDoDecrementFalse =>
    a := ConditionalHofStateActor spawn
    // flag=false => count = 0 - 1 - 2 - 3 = -6
    self assert: (a conditionalDoDecrement: false with: #(1, 2, 3)) equals: -6

  testIfFalseDoDecrementTrue =>
    a := ConditionalHofStateActor spawn
    // flag=true => count unchanged = 0
    self assert: (a conditionalDoDecrement: true with: #(1, 2, 3)) equals: 0

  // --- ifTrue:ifFalse: wrapping do: ---
  testIfTrueIfFalseDoTrue =>
    a := ConditionalHofStateActor spawn
    // flag=true => count = 0 + 1 + 2 + 3 = 6
    self assert: (a conditionalDoToggle: true with: #(1, 2, 3)) equals: 6

  testIfTrueIfFalseDoFalse =>
    a := ConditionalHofStateActor spawn
    // flag=false => count = 0 - 1 - 2 - 3 = -6
    self assert: (a conditionalDoToggle: false with: #(1, 2, 3)) equals: -6

  // --- do: wrapping ifTrue: ---
  testDoWithConditionalMutation =>
    a := ConditionalHofStateActor spawn
    // Only positives are added: 3 + 1 + 5 = 9
    self assert: (a doWithConditionalMutation: #(3, -2, 1, -4, 5)) equals: 9

  testDoWithConditionalMutationAllNegative =>
    a := ConditionalHofStateActor spawn
    // No positives => count = 0
    self assert: (a doWithConditionalMutation: #(-1, -2, -3)) equals: 0

  // --- collect: wrapping ifTrue: ---
  testCollectWithConditionalMutation =>
    a := ConditionalHofStateActor spawn
    // 3 positive items (3, 1, 5), count += 1 for each = 3
    self assert: (a collectWithConditionalMutation: #(3, -2, 1, -4, 5)) equals: 3

  // --- ifTrue: wrapping collect: ---
  testConditionalCollectTrue =>
    a := ConditionalHofStateActor spawn
    result := a conditionalCollect: true with: #(1, 2, 3)
    self assert: result equals: #(2, 4, 6)

  testConditionalCollectFalse =>
    a := ConditionalHofStateActor spawn
    result := a conditionalCollect: false with: #(1, 2, 3)
    // items unchanged (empty array)
    self assert: result equals: #()

  // --- Triple nesting: ifTrue: wrapping do: wrapping ifTrue: ---
  testTripleNestedTrue =>
    a := ConditionalHofStateActor spawn
    // flag=true, list=#(3, -2, 1) => only positives: 3 + 1 = 4
    self assert: (a tripleNested: true with: #(3, -2, 1)) equals: 4

  testTripleNestedFalse =>
    a := ConditionalHofStateActor spawn
    // flag=false => count unchanged = 0
    self assert: (a tripleNested: false with: #(3, -2, 1)) equals: 0

  // --- select: wrapping ifTrue: ---
  testSelectWithConditionalMutation =>
    a := ConditionalHofStateActor spawn
    // 3 positive items (3, 1, 5), count += 1 for each = 3
    self assert: (a selectWithConditionalMutation: #(3, -2, 1, -4, 5)) equals: 3
    self assert: a getItems equals: #(3, 1, 5)

  // --- reject: wrapping ifTrue: ---
  testRejectWithConditionalMutation =>
    a := ConditionalHofStateActor spawn
    // 2 negative items (-2, -4), count += 1 for each = 2
    self assert: (a rejectWithConditionalMutation: #(3, -2, 1, -4, 5)) equals: 2
    self assert: a getItems equals: #(3, 1, 5)

  // --- inject:into: wrapping ifTrue: ---
  testInjectWithConditionalMutation =>
    a := ConditionalHofStateActor spawn
    // Sum of positives: 3 + 1 + 5 = 9, count = 3 (three positives)
    result := a injectWithConditionalMutation: #(3, -2, 1, -4, 5)
    self assert: result equals: 9
    self assert: a getCount equals: 3

  // --- collect: with ifTrue:ifFalse: as last expression ---
  testCollectConditionalLast =>
    a := ConditionalHofStateActor spawn
    result := a collectConditionalLast: #(3, -2, 1)
    // Positives get *10 and count++; negatives pass through
    self assert: result equals: #(30, -2, 10)
    // Count should be 2 (two positive items triggered count++)
    self assert: a getCount equals: 2
    // Items should persist correctly across calls
    self assert: a getItems equals: #(30, -2, 10)

// E2E tests for Dictionary (Erlang map) methods (BT-418)

