// BT-857: Fixture for testing NLR propagation through nested HOMs
// Verifies that ^ inside a block passed through multiple HOMs propagates
// correctly through each HOM frame
//
// Value types use field: (immutable). Methods use withVisitCount: to create
// updated instances, and ^ returns the updated value through nested frames.

Value subclass: NlrNestedHom
  field: visitCount = 0

  // Inner HOM: calls aBlock for each element. Has no ^ of its own
  // When aBlock throws NLR, it propagates out of this method
  applyBlock: aBlock forEach: items => items do: [:each | aBlock value: each]

  // Outer HOM: delegates to inner HOM. Adds a second frame of indirection
  // When aBlock throws NLR through applyBlock:forEach:, it also propagates here
  applyBlockNested: aBlock forEach: items =>
    self applyBlock: aBlock forEach: items

  // Searches items for an element equal to target, through one HOM layer
  // Uses with*: to create updated self, then ^updated returns through one HOM frame
  findViaSingleHOM: target in: items =>
    updated := self withVisitCount: 1
    updated applyBlock: [:x | x =:= target ifTrue: [^updated]] forEach: items
    updated

  // Searches items for an element equal to target, through TWO HOM layers
  // Uses with*: to create updated self, then ^updated returns through two HOM frames
  findViaNestedHOM: target in: items =>
    updated := self withVisitCount: 2
    updated applyBlockNested: [:x |
      x =:= target ifTrue: [^updated]
    ] forEach: items
    updated

  visitCount => self.visitCount

