  testDictionaryCollectTransformsValues =>
    // collect: block :: Block(V, R) -> Dictionary(K, R)
    dict := #{#a => 1, #b => 2} collect: [:v | v * 10]
    self assert: (dict at: #a) equals: 10
    self assert: (dict at: #b) equals: 20

  testDictionaryIncludesChecksValue =>
    // includes: value :: V -> Boolean
    self assert: (#{#a => 1, #b => 2} includes: 1)
    self deny: (#{#a => 1} includes: 3)

  testDictionaryMerge =>
    // merge: other :: Dictionary(K, V) -> Dictionary(K, V)
    merged := #{#a => 1} merge: #{#b => 2}
    self assert: merged size equals: 2

  // ===== Set(E) =====
  testSetIncludesChecksElement =>
    // includes: element :: E -> Boolean
    s := (Set new add: 1) add: 2
    self assert: (s includes: 1)
    self deny: (s includes: 3)

  testSetAddReturnsSet =>
    // add: element :: E -> Set(E)
    s := Set new add: 42
    self assert: s size equals: 1
    self assert: (s includes: 42)

  testSetUnionCombines =>
    // union: other :: Set(E) -> Set(E)
    s1 := (Set new add: 1) add: 2
    s2 := (Set new add: 2) add: 3
    u := s1 union: s2
    self assert: u size equals: 3

  testSetIntersection =>
    // intersection: other :: Set(E) -> Set(E)
    s1 := (Set new add: 1) add: 2
    s2 := (Set new add: 2) add: 3
    i := s1 intersection: s2
    self assert: i size equals: 1
    self assert: (i includes: 2)

  testSetDifference =>
    // difference: other :: Set(E) -> Set(E)
    s1 := (Set new add: 1) add: 2
    s2 := Set new add: 2
    d := s1 difference: s2
    self assert: d size equals: 1
    self assert: (d includes: 1)

// BT-857: Tests for HOM composability (ADR 0041 Phase 5)
//
// BT-912: Tier 2 block StateAcc threading through stateful do: loop bodies
//
// The BT-912 bug: when `last := aBlock value: each` is in a stateful do:
// loop body, the Tier 2 block's NewStateAcc was discarded by codegen, so
// mutations to captured variables (e.g., `count`) were not propagated back
//
// Fixed by:
// 1. generate_local_var_assignment_in_loop: unpack {Result, NewStateAcc} from
//    Tier 2 block calls and thread NewStateAcc into the maps:put
// 2. detect_tier2_self_send: treat identifier Tier 2 block parameters as Tier 2
//    HOM arguments, enabling state threading through nested HOM delegation chains
//
// Stored blocks passed to HOMs (testStoredBlockPassedToCustomHOM) require
// type-level tracking of block variables (BT-909) and are not yet tested

TestCase subclass: HomComposabilityTest

  // Test: pure block passed to user-defined HOM — no state overhead, correct result
  // sumOf:over: with [:x | x * 2] over #(1,2,3,4,5) = 30
  testPureBlockViaHOMCorrectResult =>
    actor := HomComposabilityActor spawn
    self assert: actor testPureBlockViaHOM equals: 30

  // BT-912: Mutating block passed to user-defined HOM accumulates correctly
  // [:x | count := count + x] over 1..5 → count = 15
  testMutatingBlockViaMutatingHOM =>
    actor := HomComposabilityActor spawn
    self assert: actor testMutatingBlockInCustomLoop equals: 15

  // BT-912: Nested HOMs — outer delegates to inner, state threads through both layers
  // Same block, same items, same expected result as above
  testNestedHOMsThreadState =>
    actor := HomComposabilityActor spawn
    self assert: actor testNestedHOMsAccumulate equals: 15

// BT-1140: Tests that self.field := ... blocks promoted to Tier 2 correctly
// propagate field mutations when the block is passed through a user-defined HOM.
//
// Before this fix, field-write blocks were compiled as plain Tier 1 funs,
// so field mutations inside the block were silently discarded. The HOM
// received a fun(X) -> ... that never threaded state back to the caller.

TestCase subclass: HomFieldWriteTest

  // BT-1140: Field write block via user-defined HOM accumulates sum correctly.
  // self.sum starts at 0; applyAll: calls [:x | self.sum := self.sum + x] for
  // each of #(1, 2, 3, 4, 5); final self.sum should be 15.
  testFieldWriteViaHOM =>
    actor := HomFieldWriteActor spawn
    self assert: actor testFieldWriteViaHOM equals: 15

  // BT-1140: Two field writes in one block — both self.sum and self.count thread back.
  // The block writes two distinct actor fields on each iteration; count should be 5.
  testTwoFieldWritesViaHOM =>
    actor := HomFieldWriteActor spawn
    self assert: actor testTwoFieldWritesViaHOM equals: 5

  // BT-1140: Block with captured local mutation AND field write via user-defined HOM.
  // The block captures 'running' (local var) and also writes self.sum. Both must propagate.
  testMixedCapturedLocalAndFieldWrite =>
    actor := HomFieldWriteActor spawn
    self assert: actor testMixedCapturedLocalAndFieldWrite equals: 15

// BT-1116: Tests for HTTPClient actor class — lifecycle, state initialisation,
// and class identity. Integration tests (actual HTTP requests) are in BT-1117.

TestCase subclass: HTTPClientTest

  testSpawnAndStop =>
    // HTTPClient is an Actor subclass — spawn/stop lifecycle works
    client := HTTPClient spawn
    self assert: client isAlive
    self assert: client stop equals: #ok
    self deny: client isAlive

  testSpawnWithBaseUrl =>
    // spawnWith: sets baseUrl state; actor is alive after spawn
    client := HTTPClient spawnWith: #{#baseUrl => "https://httpbin.org"}
    self assert: client isAlive
    self assert: client stop equals: #ok

  testSpawnWithAllOptions =>
    // All three state fields are accepted by spawnWith:
    client := HTTPClient
      spawnWith: #{
        #baseUrl => "https://httpbin.org",
        #headers => #(#("X-Custom", "value")),
        #timeout => 10000
      }
    self assert: client isAlive
    self assert: client stop equals: #ok

  testSpawnWithInvalidArgumentRaisesTypeError =>
