// Stdlib tests for Json class (BT-711, updated for ADR 0060 Result migration BT-1256)

TestCase subclass: JsonTest

  testParsingPrimitiveValues =>
    self assert: (Json parse: "42") unwrap equals: 42
    // Parse a JSON float
    self assert: (Json parse: "3.14") unwrap equals: 3.14
    // Parse JSON true
    self assert: (Json parse: "true") unwrap
    // Parse JSON false
    self deny: (Json parse: "false") unwrap
    // Parse JSON null to nil
    self assert: (Json parse: "null") unwrap equals: nil

  testParsingArrays =>
    // Parse a JSON array of integers
    self assert: (Json parse: "[1, 2, 3]") unwrap equals: #(1, 2, 3)
    // Parse a nested array
    self assert: (Json parse: "[[1, 2], [3, 4]]") unwrap equals: #(#(1, 2), #(3, 4))
    // Parse a mixed array — verify size and individual access
    self assert: (Json parse: "[1, true, null]") unwrap size equals: 3
    // Parse an empty array
    self assert: (Json parse: "[]") unwrap equals: #()

  testGeneratingBeamtalkValueToJsonString =>
    // Generate JSON from a List
    self assert: (Json generate: #(1, 2, 3)) equals: "[1,2,3]"
    // Generate JSON from an Integer
    self assert: (Json generate: 42) equals: "42"
    // Generate JSON from true
    self assert: (Json generate: true) equals: "true"
    // Generate JSON from false
    self assert: (Json generate: false) equals: "false"
    // Generate JSON from nil (becomes null)
    self assert: (Json generate: nil) equals: "null"
    // Generate JSON from an empty List
    self assert: (Json generate: #()) equals: "[]"

  testRoundTripGenerateThenParse =>
    // Round-trip an integer
    self assert: (Json parse: (Json generate: 42)) unwrap equals: 42
    // Round-trip a boolean
    self assert: (Json parse: (Json generate: true)) unwrap
    // Round-trip null
    self assert: (Json parse: (Json generate: nil)) unwrap equals: nil
    // Round-trip an array
    self assert: (Json parse: (Json generate: #(1, 2, 3))) unwrap equals: #(1, 2, 3)
    // Round-trip a Dictionary
    self assert: ((Json parse: (Json generate: #{
      "name" => "Ada"
    })) unwrap at: "name") equals: "Ada"
    // Round-trip nested structures
    self
      assert: (((Json parse: (Json generate: #{
        "user" => #{"age" => 36}
      })) unwrap at: "user") at: "age")
      equals: 36

  testDictionaryGenerateAndParse =>
    // Generate JSON from a Dictionary, then verify structure
    self assert: ((Json generate: #{"a" => 1}) size > 0)
    // Generate and re-parse a Dictionary
    self assert: ((Json parse: (Json generate: #{
      "x" => 10,
      "y" => 20
    })) unwrap at: "x") equals: 10
    self assert: ((Json parse: (Json generate: #{
      "x" => 10,
      "y" => 20
    })) unwrap at: "y") equals: 20
    self assert: (Json parse: (Json generate: #{
      "x" => 10,
      "y" => 20
    })) unwrap size equals: 2
    // Dictionary with nested List
    self assert: ((Json parse: (Json generate: #{
      "items" => #(1, 2, 3)
    })) unwrap at: "items") equals: #(1, 2, 3)
    // Dictionary with boolean values
    self assert: ((Json parse: (Json generate: #{
      "active" => true
    })) unwrap at: "active")
    // Dictionary with null value
    self assert: ((Json parse: (Json generate: #{
      "value" => nil
    })) unwrap at: "value") equals: nil

  testPrettyPrinting =>
    // Pretty print produces a non-empty string
    self assert: ((Json prettyPrint: #{"a" => 1}) size > 0)
    // Pretty print produces same data as generate when re-parsed
    self assert: ((Json parse: (Json prettyPrint: #{
      "a" => 1
    })) unwrap at: "a") equals: 1

  testErrorHandling =>
    // Parse invalid JSON returns a Result error with parse_error kind
    result := Json parse: "not json"
    self deny: result isOk
    // Parse with non-string argument produces type_error (still raises)
    @expect type
    self should: [Json parse: 42] raise: #type_error

  testClassIdentity =>
    // BT-802 (ADR 0036): class on class returns a real metaclass object
    self assert: (Json class) isMeta equals: true

