// Stdlib tests for transcendental math methods (BT-712)

TestCase subclass: MathTest

  testFloatClassSideConstants =>
    self assert: Float pi equals: 3.141592653589793
    // Euler's number
    self assert: Float e equals: 2.718281828459045

  // All trig comparisons use 10-digit truncation to tolerate ULP differences
  // between ARM64 and x86_64 math libraries.
  testTrigonometricMethodsFloatInstance =>
    // sin of pi/2
    self assert: (Float pi / 2) sin equals: 1 asFloat
    // cos of pi
    self assert: (Float pi) cos equals: -1 asFloat
    // tan of pi/4
    self assert: ((Float pi / 4) tan * 10000000000.0) truncated equals: 9999999999
    // asin of 0.5
    self assert: (0.5 asin * 10000000000.0) truncated equals: 5235987755
    // acos of 0.5
    self assert: (0.5 acos * 10000000000.0) truncated equals: 10471975511
    // atan of 0.5
    self assert: (0.5 atan * 10000000000.0) truncated equals: 4636476090
    // atan2
    self assert: ((0.5 atan2: 0.5) * 10000000000.0) truncated equals: 7853981633
    // atan2 with Integer argument
    self assert: (((1 asFloat) atan2: 2) * 10000000000.0) truncated equals: 4636476090
    // sin of small value
    self assert: (0.5 sin * 10000000000.0) truncated equals: 4794255386
    // cos of small value
    self assert: (0.5 cos * 10000000000.0) truncated equals: 8775825618

  testExponentialLogarithmicMethodsFloatInstance =>
    // sqrt of 4.0
    self assert: 4.0 sqrt equals: 2 asFloat
    // sqrt of 2.0
    self assert: (2.0 sqrt * 10000000000.0) truncated equals: 14142135623
    // log of e (natural)
    self assert: ((Float e) log * 10000000000.0) truncated equals: 10000000000
    // ln of e (alias for log)
    self assert: ((Float e) ln * 10000000000.0) truncated equals: 10000000000
    // log2
    self assert: 8.0 log2 equals: 3 asFloat
    // log10
    self assert: 100.0 log10 equals: 2 asFloat
    // exp of 0.5
    self assert: (0.5 exp * 10000000000.0) truncated equals: 16487212707
    // raisedTo: (use asFloat to get a real Float receiver — 2.0 compiles to integer 2)
    self assert: ((2 asFloat) raisedTo: 10) equals: 1024 asFloat
    // raisedTo: with float exponent
    self assert: ((4 asFloat) raisedTo: 0.5) equals: 2 asFloat

  testExponentialLogarithmicMethodsIntegerInstance =>
    // Integer sqrt
    self assert: 16 sqrt equals: 4 asFloat
    // Integer sqrt non-perfect
    self assert: (2 sqrt * 10000000000.0) truncated equals: 14142135623
    // Integer log2
    self assert: 8 log2 equals: 3 asFloat
    // Integer log10
    self assert: 100 log10 equals: 2 asFloat
    // Integer exp of 2
    self assert: (2 exp * 10000000000.0) truncated equals: 73890560989
    // Integer raisedTo: with non-negative integer exponent returns Integer
    self assert: (2 raisedTo: 10) equals: 1024
    self assert: (2 raisedTo: 0) equals: 1
    self assert: (3 raisedTo: 3) equals: 27
    // Integer raisedTo: with negative exponent returns Float
    self assert: (2 raisedTo: -1) equals: 0.5
    // Integer raisedTo: with float exponent returns Float
    self assert: (4 raisedTo: 0.5) equals: 2 asFloat

  testTrigonometricIdentities =>
    // sin^2 + cos^2 = 1 (within float precision)
    x := 0.5
    result := ((x sin) * x sin) + ((x cos) * x cos)
    self assert: (result * 10000000000.0) truncated equals: 10000000000

  testDomainErrorHandling =>
    // sqrt of negative number
    self should: [(-1 asFloat) sqrt] raise: #badarith
    // log of zero
    self should: [(0 asFloat) log] raise: #badarith
    // log of negative
    self should: [(-1 asFloat) log] raise: #badarith
    // ln of zero (alias for log)
    self should: [(0 asFloat) ln] raise: #badarith
    // log2 of zero
    self should: [(0 asFloat) log2] raise: #badarith
    // log10 of zero
    self should: [(0 asFloat) log10] raise: #badarith
    // asin outside [-1, 1] range
    self should: [(2 asFloat) asin] raise: #badarith
    // acos outside [-1, 1] range
    self should: [(2 asFloat) acos] raise: #badarith

// BUnit tests for >> hierarchy walking (ADR 0033, BT-770)
//
// Verifies that >> walks the superclass chain to find inherited methods,
// matching Pharo's semantics

TestCase subclass: MethodResolverHierarchyTest

  // --- Inherited method resolution ---
  testInheritedMethodReturnsCompiledMethod =>
    // greetParent is defined on HierarchyParent, inherited by HierarchyChild
    m := HierarchyChild >> #greetParent
    self assert: m class equals: CompiledMethod
    self assert: m selector equals: #greetParent

  testInheritedMethodFromObject =>
    // isNil is defined on Object, inherited by HierarchyChild
    m := HierarchyChild >> #isNil
    self assert: m class equals: CompiledMethod
    self assert: m selector equals: #isNil

  // --- Local methods still work ---
  testLocalMethodStillReturnsCompiledMethod =>
    m := HierarchyChild >> #greetChild
    self assert: m class equals: CompiledMethod
    self assert: m selector equals: #greetChild

  // --- Local method takes precedence over inherited ---
  testLocalMethodShadowsInherited =>
    // sharedMethod is defined on both parent and child
    m := HierarchyChild >> #sharedMethod
    self assert: m class equals: CompiledMethod
    self assert: m selector equals: #sharedMethod

  // --- Non-existent methods still return nil ---
  testNonExistentMethodReturnsNil =>
    self assert: (HierarchyChild >> #nonExistent) equals: nil

  // --- Inherited method carries doc from defining class ---
  testInheritedMethodDocFromParent =>
    HierarchyParent setDocForMethod: #greetParent to: "Parent greeting"
    m := HierarchyChild >> #greetParent
    self assert: m doc equals: "Parent greeting"

