// E2E tests for Object protocol: printString, yourself, hash

TestCase subclass: ObjectProtocolTest

  testPrintstringStringRepresentationOfAnyObject =>
    self assert: 42 printString equals: "42"
    self assert: 0 printString equals: "0"
    self assert: -7 printString equals: "-7"
    // --- Strings (printString adds surrounding quotes) ---
    self assert: "hello" printString equals: """hello"""
    self assert: "" printString equals: """"""
    // --- Booleans ---
    self assert: true printString equals: "true"
    self assert: false printString equals: "false"
    // --- Nil ---
    self assert: nil printString equals: "nil"
    // --- Floats ---
    self assert: 3.14 printString equals: "3.14"
    self assert: -2.5 printString equals: "-2.5"
    // --- Lists ---
    self assert: #(1, 2, 3) printString equals: "#(1, 2, 3)"
    self assert: #() printString equals: "#()"
    // --- Blocks ---
    self assert: ([42] printString) notNil
    // --- Dictionaries ---
    self assert: #{} printString size equals: 3
    // --- Class objects (BT-477: class_send printString) ---
    self assert: 42 class printString equals: "Integer"
    self assert: "hello" class printString equals: "String"
    self assert: true class printString equals: "True"
    self assert: nil class printString equals: "UndefinedObject"

  testYourselfIdentityMethodReturnsReceiver =>
    self assert: 42 yourself equals: 42
    self assert: "hello" yourself equals: "hello"
    self assert: true yourself
    self assert: nil yourself equals: nil
    // yourself should return the same object
    self assert: (42 yourself =:= 42)
    self assert: "test" yourself =:= "test"

  testHashHashValueInteger =>
    // hash returns an integer (non-deterministic, keep wildcard)
    self assert: (42 hash) class equals: Integer
    // Same value should produce same hash
    self assert: (42 hash =:= 42 hash)
    self assert: ("hello" hash =:= "hello" hash)
    // Hash values are non-deterministic, keep wildcard
    self assert: ("hello" hash) class equals: Integer

  testRespondstoMethodExistenceCheck =>
    // Integers respond to +
    self assert: (42 respondsTo: #'+')
    // Integers respond to class (inherited from Object)
    self assert: (42 respondsTo: #class)
    // Integers do not respond to nonsense
    self deny: (42 respondsTo: #totallyFakeMethod)
    // Strings respond to size
    self assert: ("hello" respondsTo: #size)
    // Strings do not respond to nonsense
    self deny: ("hello" respondsTo: #totallyFakeMethod)
    // nil responds to isNil
    self assert: (nil respondsTo: #isNil)
    // Booleans respond to ifTrue:ifFalse:
    self assert: (true respondsTo: #ifTrue:ifFalse:)
    // Blocks respond to value
    self assert: ([1] respondsTo: #value)
    self deny: ([1] respondsTo: #invalidMethod)
    // Float responds to arithmetic operations
    self assert: (3.14 respondsTo: #'+')
    self assert: (3.14 respondsTo: #'-')
    self assert: (3.14 respondsTo: #class)
    self assert: (3.14 respondsTo: #asString)
    self assert: (3.14 respondsTo: #abs)
    self deny: (3.14 respondsTo: #nonExistent)

// BT-406: Tests the match: expression — literal arms (integer, symbol, string),
// wildcard arms, variable capture, guards (when:), and multi-arm dispatch

TestCase subclass: PatternMatchingTest

  testPatternMatchingWithGuards =>
    self assert: (42 match: [_ -> "matched"]) equals: "matched"
    // Match integer literal — first arm
    self
      assert: (1 match: [
        1 -> "one";
        2 -> "two";
        _ -> "other"
      ])
      equals: "one"
    // Match integer literal — second arm
    self
      assert: (2 match: [
        1 -> "one";
        2 -> "two";
        _ -> "other"
      ])
      equals: "two"
    // Match integer literal — fallthrough to wildcard
    self
      assert: (3 match: [
        1 -> "one";
        2 -> "two";
        _ -> "other"
      ])
      equals: "other"
    // Match symbol literal
    self
      assert: (#ok match: [
        #ok -> "success";
        #error -> "failure";
        _ -> "unknown"
      ])
      equals: "success"
    // ═══════════════════════════════════════════════════════════════════════════
    self
      assert: (#error match: [
        #ok -> "success";
        #error -> "failure";
        _ -> "unknown"
      ])
      equals: "failure"
    // Match string literal
    self
      assert: ("hello" match: [
        "hello" -> "greeting";
        _ -> "other"
      ])
      equals: "greeting"
    // Variable captures the matched value
    self assert: (42 match: [x -> x + 1]) equals: 43
    // Match with guard — positive
    self
      assert: (10 match: [
        x when: [x > 0] -> "positive";
        _ -> "non-positive"
      ])
      equals: "positive"
    // Match with guard — non-positive
    self
      assert: (-5 match: [
        x when: [x > 0] -> "positive";
        _ -> "non-positive"
      ])
      equals: "non-positive"
    // Guard with arithmetic comparison
    self
      assert: (42 match: [
        x when: [x > 100] -> "big";
        x when: [x > 10] -> "medium";
        _ -> "small"
      ])
      equals: "medium"
    // Match on expression result
    self
      assert: ((3 + 4) match: [
        7 -> "correct";
        _ -> "wrong"
      ])
      equals: "correct"
    // Match negative integer
    self
      assert: (-1 match: [
        -1 -> "minus one";
        0 -> "zero";
        _ -> "other"
      ])
      equals: "minus one"
    // ═══════════════════════════════════════════════════════════════════════════
    self
      assert: (0 match: [
        -1 -> "minus one";
        0 -> "zero";
        _ -> "other"
      ])
      equals: "zero"

  testArrayPatternInMatchArm =>
    // BT-1296: Array pattern arms — basic 2-element match
    arr := #[10, 20]
    self
      assert: (arr match: [
        #[h, t] -> h + t;
        _ -> 0
      ])
      equals: 30
    // Array arm fallthrough: subject is not an array
    self
      assert: (42 match: [
        #[a, b] -> a + b;
        _ -> 0
      ])
      equals: 0
    // Array arm fallthrough: subject is a dict (plain map — must not crash on missing key)
    self
      assert: (#{#x => 1} match: [
        #[a, b] -> a + b;
        _ -> 0
      ])
      equals: 0
    // Array arm fallthrough: wrong size
    self
      assert: (#[1, 2, 3] match: [
        #[a, b] -> a + b;
        _ -> 0
      ])
      equals: 0
    // Wildcard elements in array pattern
    self
      assert: (#[1, 2, 3] match: [
        #[_, v, _] -> v;
        _ -> 0
      ])
      equals: 2
    // Multiple array arms with different sizes
    self
      assert: (#[1, 2, 3] match: [
        #[x] -> "one";
        #[x, y] -> "two";
        #[x, y, z] -> "three";
        _ -> "other"
      ])
      equals: "three"
    // Array arm with guard — positive (exercises guard-success branch)
    self
      assert: (#[1, 2] match: [
        #[x, y] when: [x < y] -> "ascending";
        _ -> "other"
      ])
      equals: "ascending"
    // Array arm with guard — negative (exercises guard-fail fallthrough)
    self
      assert: (#[2, 1] match: [
        #[x, y] when: [x < y] -> "ascending";
        _ -> "other"
      ])
      equals: "other"

  testMapPatternInMatchArm =>
    // BT-1296: Map/Dict pattern arms
    d := #{#event => "click", #x => 5}
    self
      assert: (d match: [
        #{#event => evName} -> evName;
        _ -> "unknown"
      ])
      equals: "click"
    // Dict arm fallthrough: key missing
    self
      assert: (#{#kind => "x"} match: [
        #{#event => evName} -> evName;
        _ -> "unknown"
      ])
      equals: "unknown"
    // Dict arm fallthrough: subject is not a map
    self
      assert: (42 match: [
        #{#event => evName} -> evName;
        _ -> "unknown"
      ])
      equals: "unknown"
    // Multiple key bindings
    self
      assert: (#{#a => 1, #b => 2} match: [
        #{#a => x, #b => y} -> x + y;
        _ -> 0
      ])
      equals: 3

  testNestedArrayPatternInMatchArm =>
    // BT-1296: Nested array pattern: #[#[a, b], c] -> ...
    nested := #[#[1, 2], 3]
    self
      assert: (nested match: [
        #[#[a, b], c] -> a + b + c;
        _ -> 0
      ])
      equals: 6
    // Nested array fallthrough: inner wrong size
    self
      assert: (#[#[1, 2, 3], 4] match: [
        #[#[a, b], c] -> a + b + c;
        _ -> 0
      ])
      equals: 0

  testDuplicateVariableInArrayMatchArm =>
    // BT-1315: Duplicate variable names act as equality constraints
    // Adjacent duplicate — equal values
    self
      assert: (#[3, 3] match: [
        #[x, x] -> "equal";
        _ -> "differ"
      ])
      equals: "equal"
    // Adjacent duplicate — unequal values
    self
      assert: (#[1, 2] match: [
        #[x, x] -> "equal";
        _ -> "differ"
      ])
      equals: "differ"
    // Non-adjacent duplicate — equal values
    self
      assert: (#[5, 9, 5] match: [
        #[x, y, x] -> "match";
        _ -> "no match"
      ])
      equals: "match"
    // Non-adjacent duplicate — unequal values
    self
      assert: (#[5, 9, 7] match: [
        #[x, y, x] -> "match";
        _ -> "no match"
      ])
      equals: "no match"
    // Duplicate mixed with non-duplicate; body uses bound variable
    self
      assert: (#[4, 4, 10] match: [
        #[x, x, z] -> z;
        _ -> 0
      ])
      equals: 10

  // BT-1297: Constructor patterns for sealed types (Result ok: / Result error:)
  testConstructorPatternOkArm =>
    // ok arm matched — variable captures the wrapped value
    self
      assert: ((Result ok: 42) match: [
        Result ok: v -> v;
        Result error: _ -> 0
      ])
      equals: 42

  testConstructorPatternErrorArm =>
    // error arm matched — variable captures the error reason
    self
      assert: ((Result error: #oops) match: [
        Result ok: _ -> #none;
        Result error: e -> e
      ])
      equals: #oops

  testConstructorPatternWildcardBinding =>
    // Wildcard in value position: arm matches but nothing is bound
    self
      assert: ((Result ok: 99) match: [
        Result ok: _ -> "any ok";
        Result error: _ -> "any error"
      ])
      equals: "any ok"

  testConstructorPatternLiteralBinding =>
    // Literal in binding position: arm only matches when value equals literal
    self
      assert: ((Result ok: 0) match: [
        Result ok: 0 -> "zero";
        Result ok: _ -> "other";
        Result error: _ -> "err"
      ])
      equals: "zero"
    self
      assert: ((Result ok: 1) match: [
        Result ok: 0 -> "zero";
        Result ok: _ -> "other";
        Result error: _ -> "err"
      ])
      equals: "other"

  testConstructorPatternWithGuard =>
    // when: guard must not be consumed as a constructor keyword (BT-1297 bug fix)
    self
      assert: ((Result ok: 5) match: [
        Result ok: v when: [v > 3] -> "big";
        Result ok: _ -> "small";
        Result error: _ -> "err"
      ])
      equals: "big"
    self
      assert: ((Result ok: 1) match: [
        Result ok: v when: [v > 3] -> "big";
        Result ok: _ -> "small";
        Result error: _ -> "err"
      ])
      equals: "small"

  testConstructorPatternNegativeLiteral =>
    // Negative numeric literal in binding position (BT-1297 bug fix)
    self
      assert: ((Result ok: -1) match: [
        Result ok: -1 -> "neg one";
        Result ok: _ -> "other";
        Result error: _ -> "err"
      ])
      equals: "neg one"

  testStringKeyDictPattern =>
    // BT-1295: String keys in dict patterns — capture variable
    d := #{"event" => "click", "x" => 5}
    self
      assert: (d match: [
        #{"event" => evName} -> evName;
        _ -> "unknown"
      ])
      equals: "click"
    // String-key dict arm fallthrough: key missing
    self
      assert: (#{"kind" => "x"} match: [
        #{"event" => evName} -> evName;
        _ -> "unknown"
      ])
      equals: "unknown"
    // String-key dict arm fallthrough: subject is not a map
    self
      assert: (42 match: [
        #{"event" => evName} -> evName;
        _ -> "unknown"
      ])
      equals: "unknown"
    // String-key value equality check
    self
      assert: (d match: [
        #{"event" => "click"} -> "got click";
        #{"event" => _} -> "other event";
        _ -> "no event"
      ])
      equals: "got click"
    // Mixed symbol and string keys in one pattern
    mixed := #{#id => 42, "name" => "alice"}
    self
      assert: (mixed match: [
        #{#id => id, "name" => name} -> name;
        _ -> "no match"
      ])
      equals: "alice"
    // Multiple string-key bindings
    resp := #{"status" => "ok", "data" => 99}
    self
      assert: (resp match: [
        #{"status" => status, "data" => data} -> data;
        _ -> 0
      ])
      equals: 99
    // Negative integer literal value equality check
    neg := #{"score" => -1}
    self
      assert: (neg match: [
        #{"score" => -1} -> "neg one";
        #{"score" => _} -> "other";
        _ -> "no score"
      ])
      equals: "neg one"

  testTuplePatternInMatchArm =>
    // Tuple pattern arms — basic tagged tuple match
    t := Erlang erlang list_to_tuple: #(#ok, 42)
    self
      assert: (t match: [
        {#ok, v} -> v;
        {#error, _} -> 0;
        _ -> -1
      ])
      equals: 42
    // Tuple arm fallthrough: tag doesn't match
    t2 := Erlang erlang list_to_tuple: #(#error, "oops")
    self
      assert: (t2 match: [
        {#ok, v} -> v;
        {#error, msg} -> msg;
        _ -> "unknown"
      ])
      equals: "oops"
    // Tuple arm fallthrough: subject is not a tuple
    self
      assert: (42 match: [
        {a, b} -> a + b;
        _ -> 0
      ])
      equals: 0
    // Tuple arm with variable binding
    t3 := Erlang erlang list_to_tuple: #(10, 20)
    self
      assert: (t3 match: [
        {a, b} -> a + b;
        _ -> 0
      ])
      equals: 30

// ADR 0068 Phase 2c: Runtime protocol query tests.
// Protocol definitions (Displayable, HasSize) are in
// fixtures/protocol_test_protos.bt.

TestCase subclass: ProtocolQueriesTest

  // --- Protocol.isProtocol: ---
  testIsProtocolTrue =>
    self assert: (Protocol isProtocol: #Displayable) equals: true

  testIsProtocolFalse =>
    self assert: (Protocol isProtocol: #NotARealProtocol) equals: false

  // --- Protocol.requiredMethods: ---
  testRequiredMethodsDisplayable =>
    methods := Protocol requiredMethods: #Displayable
    self assert: (methods includes: #asString) equals: true
    self assert: (methods includes: #printString) equals: true
    self assert: methods size equals: 2

  testRequiredMethodsUnknown =>
    methods := Protocol requiredMethods: #Unknown
    self assert: methods size equals: 0

  // --- Protocol.allProtocols ---
  testAllProtocolsIncludesRegistered =>
    protos := Protocol allProtocols
    self assert: (protos includes: #Displayable) equals: true
    self assert: (protos includes: #HasSize) equals: true

  // --- conformsTo: (Behaviour method on class objects) ---
  testStringConformsToDisplayable =>
    self assert: (String conformsTo: #Displayable) equals: true

  testIntegerConformsToDisplayable =>
    self assert: (Integer conformsTo: #Displayable) equals: true

  testStringConformsToHasSize =>
    self assert: (String conformsTo: #HasSize) equals: true

  testIntegerConformsToHasSize =>
    // Integer does not have size
    self assert: (Integer conformsTo: #HasSize) equals: false

  // --- protocols (Behaviour method on class objects) ---
  testStringProtocolsIncludesDisplayable =>
    protos := String protocols
    self assert: (protos includes: #Displayable) equals: true

  testStringProtocolsIncludesHasSize =>
    protos := String protocols
    self assert: (protos includes: #HasSize) equals: true

  // --- Protocol.conformingClasses: ---

  // Note: conformingClasses with a known protocol is tested via EUnit
  // (beamtalk_protocol_registry_tests.erl). The BUnit test environment
  // makes iterating all live class processes unreliable due to gen_server
  // timeouts during hierarchy walks.
  testConformingClassesUnknownReturnsEmpty =>
    // Unknown protocol returns empty list
    classes := Protocol conformingClasses: #NonExistentProtocol
    self assert: classes size equals: 0

  // --- BT-1611: Class method protocol tests ---
  testCreatableIsProtocol =>
    self assert: (Protocol isProtocol: #Creatable) equals: true

  testRequiredMethodsCreatable =>
    // Creatable has one class method requirement: `class create`
    // Required methods returns class methods with "class " prefix
    methods := Protocol requiredMethods: #Creatable
    self assert: methods size equals: 1
    self assert: (methods includes: #'class create') equals: true

