// Tests Stream on all collection types — List, String, Set, and Dictionary —
// verifying that stream, select:, collect:, reject:, drop:, take:, do:,
// inject:into:, detect:, anySatisfy:, allSatisfy:, and Stream on: all work

TestCase subclass: StreamCollectionsTest

  testStreamOnAllCollectionTypes =>
    self assert: (#(1, 2, 3) stream) asList equals: #(1, 2, 3)
    // Empty list stream
    self assert: (#() stream) asList equals: #()
    // Single element
    self assert: (#(42) stream) asList equals: #(42)
    // Lazy pipeline on list stream
    self assert: ((#(1, 2, 3, 4, 5) stream) select: [:n |
      n > 2
    ]) asList equals: #(3, 4, 5)
    // Collect on list stream
    self assert: ((#(1, 2, 3) stream) collect: [:n |
      n * 10
    ]) asList equals: #(10, 20, 30)
    // Stream returns Stream, not List
    self assert: (#(1, 2, 3) stream) class equals: Stream
    // Chained lazy pipeline
    self
      assert: (((#(1, 2, 3, 4, 5, 6) stream) select: [:n |
        n > 2
      ]) collect: [:n | n * 10]) asList
      equals: #(30, 40, 50, 60)
    // Take on list stream
    self assert: ((#(1, 2, 3, 4, 5) stream) take: 3) equals: #(1, 2, 3)
    // Inject into on list stream
    self assert: ((#(1, 2, 3) stream) inject: 0 into: [:sum :n |
      sum + n
    ]) equals: 6
    // Detect on list stream
    self assert: ((#(1, 2, 3, 4) stream) detect: [:n | n > 2]) equals: 3
    // anySatisfy on list stream
    self assert: ((#(1, 2, 3) stream) anySatisfy: [:n | n > 2])
    // allSatisfy on list stream
    self assert: ((#(1, 2, 3) stream) allSatisfy: [:n | n > 0])
    // respondsTo: #stream
    self assert: (#(1, 2, 3) respondsTo: #stream)
    self assert: ("hello" respondsTo: #stream)
    self assert: ((Set new) respondsTo: #stream)
    // Basic string stream — characters as graphemes
    self assert: (("hello" stream) take: 3) equals: #("h", "e", "l")
    // Full string stream
    self assert: ("abc" stream) asList equals: #("a", "b", "c")
    // Empty string stream
    self assert: ("" stream) asList equals: #()
    // Single character
    self assert: ("x" stream) asList equals: #("x")
    // Select on string stream
    self assert: (("hello" stream) select: [:ch |
      ch /= "l"
    ]) asList equals: #("h", "e", "o")
    // Collect on string stream
    self assert: (("abc" stream) collect: [:ch |
      ch uppercase
    ]) asList equals: #("A", "B", "C")
    // String stream returns Stream
    self assert: ("hello" stream) class equals: Stream
    // reject on string stream
    self assert: (("hello" stream) reject: [:ch |
      ch =:= "l"
    ]) asList equals: #("h", "e", "o")
    // drop on string stream
    self assert: (("hello" stream) drop: 3) asList equals: #("l", "o")
    // do: on string stream (side effect, returns nil)
    self assert: (("abc" stream) do: [:ch | ch]) equals: nil
    // inject:into: on string stream
    self assert: (("abc" stream) inject: "" into: [:acc :ch |
      acc ++ ch
    ]) equals: "abc"
    // anySatisfy on string stream
    self assert: (("hello" stream) anySatisfy: [:ch | ch =:= "e"])
    // allSatisfy on string stream
    self assert: (("hello" stream) allSatisfy: [:ch | ch /= "z"])
    // Basic set stream
    s := ((Set new add: 3) add: 1) add: 2
    self assert: (s stream) asList equals: #(1, 2, 3)
    // Empty set stream
    self assert: (Set new stream) asList equals: #()
    // Single element set stream
    self assert: ((Set new add: 42) stream) asList equals: #(42)
    // Select on set stream
    self assert: (((((Set new add: 1) add: 2) add: 3) stream) select: [:n |
      n > 1
    ]) asList equals: #(2, 3)
    // Collect on set stream
    self assert: (((((Set new add: 1) add: 2) add: 3) stream) collect: [:n |
      n * 10
    ]) asList equals: #(10, 20, 30)
    // Set stream returns Stream
    self assert: ((Set new add: 1) stream) class equals: Stream
    // reject on set stream
    self assert: (((((Set new add: 1) add: 2) add: 3) stream) reject: [:n |
      n =:= 2
    ]) asList equals: #(1, 3)
    // drop on set stream
    self assert: (((((Set new add: 1) add: 2) add: 3) stream) drop: 1) asList equals: #(2, 3)
    // take on set stream
    self assert: (((((Set new add: 1) add: 2) add: 3) stream) take: 2) equals: #(1, 2)
    // do: on set stream (returns nil)
    self assert: (((Set new add: 1) stream) do: [:n | n]) equals: nil
    // inject:into: on set stream
    self
      assert: (((((Set new add: 1) add: 2) add: 3) stream) inject: 0 into: [:sum :n |
        sum + n
      ])
      equals: 6
    // detect on set stream
    self assert: (((((Set new add: 1) add: 2) add: 3) stream) detect: [:n |
      n > 1
    ]) equals: 2
    // anySatisfy on set stream
    self assert: ((((Set new add: 1) add: 2) stream) anySatisfy: [:n | n > 1])
    // allSatisfy on set stream
    self assert: ((((Set new add: 1) add: 2) stream) allSatisfy: [:n | n > 0])
    // Stream on: with string
    self assert: (Stream on: "abc") asList equals: #("a", "b", "c")
    // Stream on: with set
    self assert: (Stream on: ((Set new add: 1) add: 2)) asList equals: #(1, 2)

// Tests the Stream class — from:, from:by:, on: constructors; lazy pipeline
// ops (select:, collect:, reject:, drop:); terminals (take:, asList, do:,
// inject:into:, detect:, anySatisfy:, allSatisfy:); and empty-stream behaviour

TestCase subclass: StreamTest

  testStreamConstructorsAndPipelines =>
    self assert: ((Stream from: 1) take: 5) equals: #(1, 2, 3, 4, 5)
    self assert: ((Stream from: 10) take: 3) equals: #(10, 11, 12)
    self assert: ((Stream from: 0) take: 1) equals: #(0)
    self assert: ((Stream from: -3) take: 4) equals: #(-3, -2, -1, 0)
    // Stream from:by: — step function stream
    self assert: ((Stream from: 1 by: [:n |
      n * 2
    ]) take: 5) equals: #(1, 2, 4, 8, 16)
    self assert: ((Stream from: 0 by: [:n |
      n + 10
    ]) take: 4) equals: #(0, 10, 20, 30)
    self assert: ((Stream from: 100 by: [:n |
      n - 1
    ]) take: 3) equals: #(100, 99, 98)
    // Stream on: — from collection
    self assert: (Stream on: #(1, 2, 3)) asList equals: #(1, 2, 3)
    self assert: (Stream on: #()) asList equals: #()
    self assert: (Stream on: #(42)) asList equals: #(42)
    // select: — filter
    self assert: ((Stream on: #(1, 2, 3, 4, 5)) select: [:n |
      n > 3
    ]) asList equals: #(4, 5)
    self assert: ((Stream on: #(1, 2, 3, 4, 5, 6)) select: [:n |
      n isEven
    ]) asList equals: #(2, 4, 6)
    // select: on empty
    self assert: ((Stream on: #()) select: [:n | n > 0]) asList equals: #()
    // collect: — transform
    self assert: ((Stream on: #(1, 2, 3)) collect: [:n |
      n * 10
    ]) asList equals: #(10, 20, 30)
    self assert: ((Stream on: #(1, 2, 3)) collect: [:n |
      n + 100
    ]) asList equals: #(101, 102, 103)
    // reject: — inverse filter
    self assert: ((Stream on: #(1, 2, 3, 4, 5)) reject: [:n |
      n > 3
    ]) asList equals: #(1, 2, 3)
    self assert: ((Stream on: #(1, 2, 3, 4)) reject: [:n |
      n isEven
    ]) asList equals: #(1, 3)
    // drop: — skip first N
    self assert: ((Stream on: #(1, 2, 3, 4, 5)) drop: 2) asList equals: #(3, 4, 5)
    self assert: ((Stream on: #(1, 2, 3)) drop: 0) asList equals: #(1, 2, 3)
    self assert: ((Stream on: #(1, 2, 3)) drop: 5) asList equals: #()
    // take: — first N elements
    self assert: ((Stream from: 1) take: 0) equals: #()
    self assert: ((Stream from: 1) take: 3) equals: #(1, 2, 3)
    // take: on finite stream (fewer elements than requested)
    self assert: ((Stream on: #(1, 2)) take: 10) equals: #(1, 2)
    // do: — iterate with side effects
    self assert: ((Stream on: #(1, 2, 3)) do: [:n | n]) equals: nil
    // inject:into: — fold/reduce
    self assert: ((Stream on: #(1, 2, 3, 4)) inject: 0 into: [:sum :n |
      sum + n
    ]) equals: 10
    self assert: ((Stream on: #(1, 2, 3)) inject: 1 into: [:product :n |
      product * n
    ]) equals: 6
    self assert: ((Stream on: #()) inject: 42 into: [:acc :n |
      acc + n
    ]) equals: 42
    // detect: — first matching element
    self assert: ((Stream on: #(1, 2, 3, 4, 5)) detect: [:n | n > 3]) equals: 4
    self assert: ((Stream on: #(1, 2, 3)) detect: [:n | n > 10]) equals: nil
    // asList — materialize
    self assert: (Stream on: #(10, 20, 30)) asList equals: #(10, 20, 30)
    // anySatisfy: — any match?
    self assert: ((Stream on: #(1, 2, 3)) anySatisfy: [:n | n > 2])
    self deny: ((Stream on: #(1, 2, 3)) anySatisfy: [:n | n > 10])
    self deny: ((Stream on: #()) anySatisfy: [:n | n > 0])
    // allSatisfy: — all match?
    self assert: ((Stream on: #(1, 2, 3)) allSatisfy: [:n | n > 0])
    self deny: ((Stream on: #(1, 2, 3)) allSatisfy: [:n | n > 2])
    self assert: ((Stream on: #()) allSatisfy: [:n | n > 0])
    // Chained lazy ops on infinite stream
    self assert: (((Stream from: 1) select: [:n |
      n isEven
    ]) take: 5) equals: #(2, 4, 6, 8, 10)
    self assert: (((Stream from: 1) collect: [:n |
      n * n
    ]) take: 5) equals: #(1, 4, 9, 16, 25)
    // Multi-step pipeline
    self assert: ((((Stream from: 1) select: [:n |
      n isEven
    ]) collect: [:n | n * n]) take: 4) equals: #(4, 16, 36, 64)
    // Pipeline with drop
    self assert: (((Stream from: 1) drop: 5) take: 3) equals: #(6, 7, 8)
    // inject on finite stream
    self assert: ((Stream on: #(1, 2, 3, 4, 5)) inject: 0 into: [:sum :n |
      sum + n
    ]) equals: 15
    (Stream from: 1) printString
    // => _
    (Stream on: #(1, 2, 3)) printString
    // => _
    // Pipeline description
    ((Stream from: 1) select: [:n | n isEven]) printString
    // => _
    (Stream from: 1) printString
    // => _
    self assert: (Stream from: 1) class equals: Stream
    self assert: ((Stream on: #()) take: 5) equals: #()
    self assert: (Stream on: #()) asList equals: #()
    self assert: ((Stream on: #()) detect: [:x | x > 0]) equals: nil
    self deny: ((Stream on: #()) anySatisfy: [:x | x > 0])
    self assert: ((Stream on: #()) allSatisfy: [:x | x > 0])
    self assert: ((Stream on: #()) inject: 0 into: [:acc :x |
      acc + x
    ]) equals: 0
    self assert: ((Stream on: #(1, 2, 3)) drop: 10) asList equals: #()

  testInstanceMethodTypeErrors =>
    // Instance method type errors (constructor errors cannot be tested due to gen_server limitation)
    @expect type
    self should: [(Stream from: 1) select: "not a block"] raise: #type_error
    @expect type
    self should: [(Stream from: 1) collect: 42] raise: #type_error
    // BT-765: take: with non-integer argument raises type_error
    @expect all
    self should: [(Stream from: 1) take: "five"] raise: #type_error

// BT-1562: Strict equality (=:=) and strict inequality (=/=).
// Erlang's =:= is exact equality — 5 =:= 5.0 is false because they are
// different types. =/= is the complement: (x =/= y) iff not (x =:= y).
// Loose equality (==) coerces, so 5 == 5.0 is true.

TestCase subclass: StrictEqualityTest

  // --- Integer =:= / =/= ---
  testIntegerStrictEqualsSameInteger => self assert: (5 =:= 5)

  testIntegerStrictNotEqualsFloat => self deny: (5 =:= 5.0)

  testIntegerInequalityDifferentValues =>
    @expect type
    self assert: (1 =/= 2)

  testIntegerInequalitySameValue =>
    @expect type
    self deny: (5 =/= 5)

  testIntegerInequalityIntVsFloat =>
    @expect type
    self assert: (5 =/= 5.0)

  // --- Float =:= / =/= ---
  testFloatStrictEqualsSameFloat => self assert: (5.0 =:= 5.0)

  testFloatStrictNotEqualsInteger => self deny: (5.0 =:= 5)

  testFloatInequalityDifferentValues =>
    @expect type
    self assert: (1.0 =/= 2.0)

  testFloatInequalitySameValue =>
    @expect type
    self deny: (3.14 =/= 3.14)

  // --- Loose equality (==) coerces across int/float ---
  testLooseEqualityCoercesIntFloat => self assert: (5 == 5.0)

  // --- Zero and negative edge cases ---
  testZeroIntNotStrictEqualsZeroFloat => self deny: (0 =:= 0.0)

  testZeroIntStrictInequalityZeroFloat =>
    @expect type
    self assert: (0 =/= 0.0)

  testNegativeIntNotStrictEqualsNegativeFloat => self deny: (-1 =:= -1.0)

  // --- String =:= / =/= ---
  testStringStrictEqualsSameString => self assert: ("abc" =:= "abc")

  testStringStrictNotEqualsDifferent => self deny: ("abc" =:= "xyz")

  testStringInequalityDifferent =>
    @expect type
    self assert: ("abc" =/= "xyz")

  testStringInequalitySame =>
    @expect type
    self deny: ("abc" =/= "abc")

  // --- Symbol =:= / =/= ---
  testSymbolStrictEqualsSame => self assert: (#hello =:= #hello)

  testSymbolStrictNotEqualsDifferent => self deny: (#hello =:= #world)

  testSymbolInequalityDifferent =>
    @expect type
    self assert: (#hello =/= #world)

  testSymbolInequalitySame =>
    @expect type
    self deny: (#hello =/= #hello)

// String/Binary inheritance tests — verify byte-level methods inherited
// from Binary work correctly on String instances (ADR 0069 Phase 3b, BT-1595)

TestCase subclass: StringBinaryInheritanceTest

  // ═══════════════════════════════════════════════════════════════════
  // Grapheme-level overrides still work (no regressions)
  // ═══════════════════════════════════════════════════════════════════
  testAtReturnsGraphemes =>
    // String's at: returns graphemes, not bytes
    self assert: ("hello" at: 1) equals: "h"
    self assert: ("hello" at: 5) equals: "o"
    // Multi-byte grapheme: "café" — é is 2 bytes but 1 grapheme
    self assert: ("café" at: 4) equals: "é"

  testSizeReturnsGraphemeCount =>
    // String's size returns grapheme count, not byte count
    self assert: "hello" size equals: 5
    self assert: "café" size equals: 4

  testDoIteratesGraphemes =>
    // String's do: iterates graphemes, not bytes (returns nil)
    self assert: ("hi" do: [:ch | nil]) equals: nil

  testCollectOperatesOnGraphemes =>
    self assert: ("hi" collect: [:ch | ch uppercase]) equals: "HI"

  testSelectOperatesOnGraphemes =>
    self assert: ("hello" select: [:ch | ch /= "l"]) equals: "heo"

  testRejectOperatesOnGraphemes =>
    self assert: ("hello" reject: [:ch | ch =:= "l"]) equals: "heo"

  // ═══════════════════════════════════════════════════════════════════
  // Byte-level methods inherited from Binary
  // ═══════════════════════════════════════════════════════════════════
  testByteAtReturnsBytes =>
    // byteAt: uses 0-based indexing and returns byte values
    self assert: ("hello" byteAt: 0) equals: 104
    self assert: ("hello" byteAt: 1) equals: 101
    self assert: ("hello" byteAt: 4) equals: 111

  testByteSizeReturnsBytes =>
    // byteSize returns byte count (same as size for ASCII)
    self assert: "hello" byteSize equals: 5

  testByteSizeVsSize =>
    // "café" — é is 2 bytes (C3 A9) but 1 grapheme
    self assert: "café" byteSize equals: 5
    self assert: "café" size equals: 4

  testPartReturnsBinary =>
    // part:size: returns a Binary slice (not String)
    result := "hello" part: 0 size: 3
    self assert: result equals: "hel"

  testConcatReturnsBinary =>
    // concat: returns Binary (not String)
    result := "hello" concat: "world"
    self assert: result equals: "helloworld"

  testToBytes =>
    // toBytes returns list of byte integers
    self assert: "hello" toBytes equals: #(104, 101, 108, 108, 111)

  testAsStringOnString =>
    // asString on a String is a no-op, returns the string itself
    self assert: "hello" asString equals: "hello"

  testAsStringUncheckedOnString =>
    // asStringUnchecked on a String returns the string itself
    self assert: "hello" asStringUnchecked equals: "hello"

// Stdlib tests for string interpolation (ADR 0023 Phase 3, BT-558)

TestCase subclass: StringInterpolationTest

  testBasicStringTestsNoInterpolationZeroOverhead =>
    self assert: "Hello" equals: "Hello"

  testVariableInterpolation =>
    // Simple variable interpolation
    name := "World"
    self assert: name equals: "World"
    self assert: "Hello, {name}!" equals: "Hello, World!"
    // Variable at start
    self assert: "{name} says hi" equals: "World says hi"
    // Variable at end
    self assert: "Hi {name}" equals: "Hi World"
    // Only variable (no literal segments)
    self assert: "{name}" equals: "World"

  testExpressionInterpolation =>
    // Arithmetic expression
    self assert: "Sum: {2 + 3}" equals: "Sum: 5"

  testPrintstringConversion =>
    // Integer printString
    self assert: "Age: {30}" equals: "Age: 30"
    // Boolean interpolation
    self assert: "Flag: {true}" equals: "Flag: true"
    self assert: "Flag: {false}" equals: "Flag: false"
    // Nil interpolation
    self assert: "Value: {nil}" equals: "Value: nil"
    // Symbol interpolation (displayString: no # prefix)
    self assert: "Symbol: {#hello}" equals: "Symbol: hello"

  testNestedMessageSends =>
    // String message in interpolation
    self assert: "Length: {"hello" length}" equals: "Length: 5"

  testMultipleInterpolations =>
    // Two variables
    first := "Alice"
    self assert: first equals: "Alice"
    last := "Bob"
    self assert: last equals: "Bob"
    self assert: "Name: {first} {last}" equals: "Name: Alice Bob"
    // Mixed literals and expressions
    self assert: "a{1}b{2}c" equals: "a1b2c"
    // Adjacent interpolations
    self assert: "{first}{last}" equals: "AliceBob"

  testEscapedBraces =>
    // \{ produces literal {; backslash consumed, one-char result
    // Value check: both sides are "\{" so both produce { — verifies it compiles and runs
    self assert: "\{" equals: "\{"
    self assert: "\{" size equals: 1
    // \} and bare } are equivalent — \} normalizes to } in formatted source
    self assert: "}" size equals: 1
    // Combined: a\{b\}c → a{b}c (5 chars)
    self assert: "a\{b}c" size equals: 5

  testEmptyAndEdgeCases =>
    // Empty string
    self assert: "" equals: ""
    // String with only literals
    self assert: "no interpolation here" equals: "no interpolation here"

  testUnicodeContent =>
    // Unicode in literal segments
    self assert: "Hello 🎉" equals: "Hello 🎉"
    // Unicode variable
    emoji := "🚀"
    self assert: emoji equals: "🚀"
    self assert: "Launch: {emoji}" equals: "Launch: 🚀"
    // CJK characters
    self assert: "日本語: {42}" equals: "日本語: 42"

  testActorInterpolationAutoAwait =>
    // Actor printString auto-awaits the future
    c := Counter spawn
    self assert: "Actor: {c}" equals: "Actor: a Counter"

